import Database from 'better-sqlite3';
import path from 'path';
import type { DatabaseConfig } from '../types';

const DEFAULT_CONFIG: DatabaseConfig = {
  filename: path.join(__dirname, '..', 'data', 'ecommerce.db'),
  verbose: false,
};

let db: Database.Database | null = null;

export function getDatabase(config?: Partial<DatabaseConfig>): Database.Database {
  if (db) {
    return db;
  }

  const mergedConfig: DatabaseConfig = { ...DEFAULT_CONFIG, ...config };

  const dir = path.dirname(mergedConfig.filename);
  const fs = require('fs');
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
  }

  db = new Database(mergedConfig.filename);

  if (mergedConfig.verbose) {
    db.pragma('journal_mode = WAL');
    db.pragma('foreign_keys = ON');
  } else {
    db.pragma('journal_mode = WAL');
    db.pragma('foreign_keys = ON');
  }

  initializeTables(db);

  return db;
}

function initializeTables(db: Database.Database): void {
  db.exec(`
    CREATE TABLE IF NOT EXISTS users (
      id TEXT PRIMARY KEY,
      username TEXT NOT NULL UNIQUE,
      email TEXT NOT NULL UNIQUE,
      password_hash TEXT NOT NULL,
      role TEXT NOT NULL DEFAULT 'user' CHECK(role IN ('user', 'admin')),
      created_at TEXT NOT NULL DEFAULT (datetime('now')),
      updated_at TEXT NOT NULL DEFAULT (datetime('now'))
    );

    CREATE TABLE IF NOT EXISTS products (
      id TEXT PRIMARY KEY,
      name TEXT NOT NULL,
      description TEXT NOT NULL DEFAULT '',
      price REAL NOT NULL CHECK(price >= 0),
      stock INTEGER NOT NULL DEFAULT 0 CHECK(stock >= 0),
      image_url TEXT,
      category TEXT NOT NULL DEFAULT '',
      created_at TEXT NOT NULL DEFAULT (datetime('now')),
      updated_at TEXT NOT NULL DEFAULT (datetime('now'))
    );

    CREATE TABLE IF NOT EXISTS cart_items (
      id TEXT PRIMARY KEY,
      user_id TEXT NOT NULL,
      product_id TEXT NOT NULL,
      quantity INTEGER NOT NULL DEFAULT 1 CHECK(quantity > 0),
      created_at TEXT NOT NULL DEFAULT (datetime('now')),
      updated_at TEXT NOT NULL DEFAULT (datetime('now')),
      FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
      FOREIGN KEY (product_id) REFERENCES products(id) ON DELETE CASCADE,
      UNIQUE(user_id, product_id)
    );

    CREATE TABLE IF NOT EXISTS orders (
      id TEXT PRIMARY KEY,
      user_id TEXT NOT NULL,
      total_amount REAL NOT NULL DEFAULT 0 CHECK(total_amount >= 0),
      status TEXT NOT NULL DEFAULT 'pending' CHECK(status IN ('pending', 'paid', 'shipped', 'delivered', 'cancelled')),
      shipping_address TEXT NOT NULL DEFAULT '',
      created_at TEXT NOT NULL DEFAULT (datetime('now')),
      updated_at TEXT NOT NULL DEFAULT (datetime('now')),
      FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
    );

    CREATE TABLE IF NOT EXISTS order_items (
      id TEXT PRIMARY KEY,
      order_id TEXT NOT NULL,
      product_id TEXT NOT NULL,
      quantity INTEGER NOT NULL CHECK(quantity > 0),
      price REAL NOT NULL CHECK(price >= 0),
      created_at TEXT NOT NULL DEFAULT (datetime('now')),
      FOREIGN KEY (order_id) REFERENCES orders(id) ON DELETE CASCADE,
      FOREIGN KEY (product_id) REFERENCES products(id) ON DELETE CASCADE
    );

    CREATE INDEX IF NOT EXISTS idx_cart_items_user_id ON cart_items(user_id);
    CREATE INDEX IF NOT EXISTS idx_cart_items_product_id ON cart_items(product_id);
    CREATE INDEX IF NOT EXISTS idx_orders_user_id ON orders(user_id);
    CREATE INDEX IF NOT EXISTS idx_order_items_order_id ON order_items(order_id);
    CREATE INDEX IF NOT EXISTS idx_order_items_product_id ON order_items(product_id);
    CREATE INDEX IF NOT EXISTS idx_products_category ON products(category);
  `);
}

export function closeDatabase(): void {
  if (db) {
    db.close();
    db = null;
  }
}

export default getDatabase;

import express, { type Express, type Request, type Response, type NextFunction } from 'express';
import cors from 'cors';
import jwt from 'jsonwebtoken';
import Database from 'better-sqlite3';
import path from 'path';
import type { ServerConfig, CorsOptions, ServerApp, ExpressApp } from '../types';

// ============================================================
// 路由导入
import authRoutes from './routes/auth';
import productRoutes from './routes/products';
import cartRoutes from './routes/cart';
import orderRoutes from './routes/orders';

// ============================================================
// 配置
const config: ServerConfig = {
  port: Number(process.env.PORT) || 3000,
  jwtSecret: process.env.JWT_SECRET || 'ecommerce-jwt-secret-key-2024',
  jwtExpiresIn: process.env.JWT_EXPIRES_IN || '24h',
  corsOrigin: process.env.CORS_ORIGIN || 'http://localhost:5173',
  dbFilename: process.env.DB_FILENAME || 'ecommerce.db',
};

// ============================================================
// CORS 配置
const corsOptions: CorsOptions = {
  origin: config.corsOrigin,
  methods: ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS'],
  allowedHeaders: ['Content-Type', 'Authorization', 'X-Requested-With'],
  credentials: true,
};

// ============================================================
// JWT 载荷接口
export interface JwtPayload {
  userId: number;
  email: string;
  role: string;
}

// Express Request 扩展
declare global {
  namespace Express {
    interface Request {
      user?: JwtPayload;
    }
  }
}

// ============================================================
// 数据库初始化
const dbPath = path.resolve(__dirname, '..', config.dbFilename);
export const db = new Database(dbPath);

// 启用 WAL 模式提升并发性能
db.pragma('journal_mode = WAL');
db.pragma('foreign_keys = ON');

// ============================================================
// 初始化数据库表
function initDatabase(): void {
  db.exec(`
    CREATE TABLE IF NOT EXISTS users (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      email TEXT UNIQUE NOT NULL,
      password TEXT NOT NULL,
      name TEXT NOT NULL,
      role TEXT DEFAULT 'customer' CHECK(role IN ('customer', 'admin')),
      avatar TEXT,
      phone TEXT,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
    );

    CREATE TABLE IF NOT EXISTS categories (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      name TEXT NOT NULL,
      slug TEXT UNIQUE NOT NULL,
      description TEXT,
      image TEXT,
      parent_id INTEGER,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      FOREIGN KEY (parent_id) REFERENCES categories(id) ON DELETE SET NULL
    );

    CREATE TABLE IF NOT EXISTS products (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      name TEXT NOT NULL,
      slug TEXT UNIQUE NOT NULL,
      description TEXT,
      price REAL NOT NULL CHECK(price >= 0),
      original_price REAL CHECK(original_price >= 0),
      stock INTEGER DEFAULT 0 CHECK(stock >= 0),
      category_id INTEGER,
      images TEXT DEFAULT '[]',
      specifications TEXT DEFAULT '{}',
      is_active INTEGER DEFAULT 1,
      sales_count INTEGER DEFAULT 0,
      rating REAL DEFAULT 0 CHECK(rating >= 0 AND rating <= 5),
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      FOREIGN KEY (category_id) REFERENCES categories(id) ON DELETE SET NULL
    );

    CREATE TABLE IF NOT EXISTS cart_items (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      user_id INTEGER NOT NULL,
      product_id INTEGER NOT NULL,
      quantity INTEGER NOT NULL DEFAULT 1 CHECK(quantity > 0),
      selected INTEGER DEFAULT 1,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
      FOREIGN KEY (product_id) REFERENCES products(id) ON DELETE CASCADE,
      UNIQUE(user_id, product_id)
    );

    CREATE TABLE IF NOT EXISTS orders (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      order_no TEXT UNIQUE NOT NULL,
      user_id INTEGER NOT NULL,
      status TEXT DEFAULT 'pending' CHECK(status IN ('pending', 'paid', 'shipped', 'delivered', 'cancelled', 'refunding', 'refunded')),
      total_amount REAL NOT NULL,
      shipping_address TEXT NOT NULL,
      contact_name TEXT NOT NULL,
      contact_phone TEXT NOT NULL,
      remark TEXT,
      paid_at DATETIME,
      shipped_at DATETIME,
      delivered_at DATETIME,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
    );

    CREATE TABLE IF NOT EXISTS order_items (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      order_id INTEGER NOT NULL,
      product_id INTEGER NOT NULL,
      product_name TEXT NOT NULL,
      product_image TEXT,
      price REAL NOT NULL,
      quantity INTEGER NOT NULL,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      FOREIGN KEY (order_id) REFERENCES orders(id) ON DELETE CASCADE,
      FOREIGN KEY (product_id) REFERENCES products(id)
    );

    CREATE TABLE IF NOT EXISTS addresses (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      user_id INTEGER NOT NULL,
      name TEXT NOT NULL,
      phone TEXT NOT NULL,
      province TEXT NOT NULL,
      city TEXT NOT NULL,
      district TEXT NOT NULL,
      detail TEXT NOT NULL,
      is_default INTEGER DEFAULT 0,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
    );

    CREATE TABLE IF NOT EXISTS reviews (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      user_id INTEGER NOT NULL,
      product_id INTEGER NOT NULL,
      order_id INTEGER NOT NULL,
      rating INTEGER NOT NULL CHECK(rating >= 1 AND rating <= 5),
      content TEXT,
      images TEXT DEFAULT '[]',
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
      FOREIGN KEY (product_id) REFERENCES products(id) ON DELETE CASCADE,
      FOREIGN KEY (order_id) REFERENCES orders(id) ON DELETE CASCADE,
      UNIQUE(user_id, product_id, order_id)
    );

    -- 创建索引
    CREATE INDEX IF NOT EXISTS idx_products_category ON products(category_id);
    CREATE INDEX IF NOT EXISTS idx_products_slug ON products(slug);
    CREATE INDEX IF NOT EXISTS idx_cart_user ON cart_items(user_id);
    CREATE INDEX IF NOT EXISTS idx_orders_user ON orders(user_id);
    CREATE INDEX IF NOT EXISTS idx_orders_status ON orders(status);
    CREATE INDEX IF NOT EXISTS idx_orders_no ON orders(order_no);
    CREATE INDEX IF NOT EXISTS idx_order_items_order ON order_items(order_id);
    CREATE INDEX IF NOT EXISTS idx_reviews_product ON reviews(product_id);
    CREATE INDEX IF NOT EXISTS idx_addresses_user ON addresses(user_id);
  `);

  // 插入默认分类（如果不存在）
  const categoryCount = db.prepare('SELECT COUNT(*) as count FROM categories').get() as { count: number };
  if (categoryCount.count === 0) {
    const insertCategory = db.prepare(
      'INSERT INTO categories (name, slug, description) VALUES (?, ?, ?)'
    );
    const categories = [
      { name: '电子产品', slug: 'electronics', description: '手机、电脑、数码配件等' },
      { name: '服装鞋包', slug: 'clothing', description: '男装、女装、鞋靴、箱包' },
      { name: '家居生活', slug: 'home-living', description: '家具、家纺、厨具、装饰' },
      { name: '美妆护肤', slug: 'beauty', description: '护肤、彩妆、香水、个人护理' },
      { name: '食品生鲜', slug: 'food', description: '零食、生鲜、饮料、特产' },
      { name: '图书文创', slug: 'books', description: '图书、文具、文创产品' },
    ];

    const insertMany = db.transaction(() => {
      for (const cat of categories) {
        insertCategory.run(cat.name, cat.slug, cat.description);
      }
    });
    insertMany();
  }

  console.log('[Database] 数据库初始化完成');
}

// ============================================================
// JWT 认证中间件
function authenticate(req: Request, res: Response, next: NextFunction): void {
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    res.status(401).json({
      success: false,
      message: '未提供认证令牌',
    });
    return;
  }

  const token = authHeader.split(' ')[1];

  try {
    const decoded = jwt.verify(token, config.jwtSecret) as JwtPayload;
    req.user = decoded;
    next();
  } catch (error) {
    if (error instanceof jwt.TokenExpiredError) {
      res.status(401).json({
        success: false,
        message: '认证令牌已过期，请重新登录',
      });
      return;
    }
    if (error instanceof jwt.JsonWebTokenError) {
      res.status(401).json({
        success: false,
        message: '无效的认证令牌',
      });
      return;
    }
    res.status(500).json({
      success: false,
      message: '认证服务异常',
    });
  }
}

// 可选认证中间件 - 不强制要求登录，但如果提供了有效 token 则解析用户信息
function optionalAuth(req: Request, _res: Response, next: NextFunction): void {
  const authHeader = req.headers.authorization;

  if (authHeader && authHeader.startsWith('Bearer ')) {
    const token = authHeader.split(' ')[1];
    try {
      const decoded = jwt.verify(token, config.jwtSecret) as JwtPayload;
      req.user = decoded;
    } catch {
      // 忽略无效 token
    }
  }
  next();
}

// 管理员权限中间件
function requireAdmin(req: Request, res: Response, next: NextFunction): void {
  if (!req.user || req.user.role !== 'admin') {
    res.status(403).json({
      success: false,
      message: '权限不足，需要管理员权限',
    });
    return;
  }
  next();
}

// ============================================================
// 404 处理中间件
function notFoundHandler(_req: Request, res: Response): void {
  res.status(404).json({
    success: false,
    message: '请求的资源不存在',
    code: 'NOT_FOUND',
  });
}

// ============================================================
// 全局错误处理中间件
function errorHandler(err: Error, _req: Request, res: Response, _next: NextFunction): void {
  console.error('[Error]', err.message);
  console.error(err.stack);

  // SQLite 唯一约束错误
  if (err.message?.includes('UNIQUE constraint failed')) {
    res.status(409).json({
      success: false,
      message: '数据已存在，请勿重复提交',
      code: 'CONFLICT',
    });
    return;
  }

  // JSON 解析错误
  if (err instanceof SyntaxError && 'body' in err) {
    res.status(400).json({
      success: false,
      message: '请求体 JSON 格式错误',
      code: 'INVALID_JSON',
    });
    return;
  }

  // 请求体过大
  if (err.type === 'entity.too.large') {
    res.status(413).json({
      success: false,
      message: '请求体过大',
      code: 'PAYLOAD_TOO_LARGE',
    });
    return;
  }

  res.status(500).json({
    success: false,
    message: process.env.NODE_ENV === 'production' ? '服务器内部错误' : err.message,
    code: 'INTERNAL_ERROR',
  });
}

// ============================================================
// Express 应用创建
function createApp(): ExpressApp {
  const app: Express = express();

  // CORS
  app.use(cors(corsOptions));

  // Body 解析
  app.use(express.json({ limit: '10mb' }));
  app.use(express.urlencoded({ extended: true, limit: '10mb' }));

  // 静态文件服务（上传的图片等）
  app.use('/uploads', express.static(path.resolve(__dirname, '..', 'uploads')));

  // 请求日志（开发环境）
  if (process.env.NODE_ENV !== 'production') {
    app.use((req: Request, _res: Response, next: NextFunction) => {
      const timestamp = new Date().toISOString();
      console.log(`[${timestamp}] ${req.method} ${req.url}`);
      next();
    });
  }

  // 健康检查
  app.get('/api/health', (_req: Request, res: Response) => {
    res.json({
      success: true,
      message: '服务运行正常',
      timestamp: new Date().toISOString(),
      uptime: process.uptime(),
    });
  });

  // ============================================================
  // API 路由挂载
  app.use('/api/v1/auth', authRoutes);
  app.use('/api/v1/products', optionalAuth, productRoutes);
  app.use('/api/v1/cart', authenticate, cartRoutes);
  app.use('/api/v1/orders', authenticate, orderRoutes);

  // ============================================================
  // 404 与错误处理
  app.use(notFoundHandler);
  app.use(errorHandler);

  return { app, config } as unknown as ExpressApp;
}

// ============================================================
// 服务器启动
function start(): void {
  // 初始化数据库
  initDatabase();

  const appInstance = createApp();
  const app = (appInstance as unknown as { app: Express }).app;

  app.listen(config.port, () => {
    console.log('='.repeat(50));
    console.log(`🚀 电商平台服务已启动`);
    console.log(`📍 地址: http://localhost:${config.port}`);
    console.log(`📡 API:  http://localhost:${config.port}/api/v1`);
    console.log(`💚 健康检查: http://localhost:${config.port}/api/health`);
    console.log(`🌍 环境: ${process.env.NODE_ENV || 'development'}`);
    console.log('='.repeat(50));
  });
}

// ============================================================
// 导出
export { config, authenticate, optionalAuth, requireAdmin };
export { db, initDatabase };

// 直接启动
if (require.main === module || process.argv[1]?.includes('index')) {
  start();
}

export default { start, config, db };

import { Router, Request, Response, NextFunction } from 'express';
import bcrypt from 'bcryptjs';
import jwt from 'jsonwebtoken';
import { v4 as uuidv4 } from 'uuid';
import db from '../db';
import type {
  RegisterRequest,
  LoginRequest,
  AuthResponse,
  User,
  JwtPayload,
  AuthMiddlewareRequest,
} from '../types';

const router = Router();

const JWT_SECRET = process.env.JWT_SECRET || 'dev-jwt-secret-change-in-production';
const JWT_EXPIRES_IN = '7d';
const SALT_ROUNDS = 10;

// ============================================================
// Auth Middleware
// ============================================================

export function authMiddleware(
  req: AuthMiddlewareRequest,
  res: Response,
  next: NextFunction
): void {
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    res.status(401).json({
      success: false,
      message: '未提供认证令牌',
    });
    return;
  }

  const token = authHeader.split(' ')[1];

  try {
    const decoded = jwt.verify(token, JWT_SECRET) as JwtPayload;
    req.user = decoded;
    next();
  } catch {
    res.status(401).json({
      success: false,
      message: '令牌无效或已过期',
    });
  }
}

// ============================================================
// Helpers
// ============================================================

function generateToken(user: User): string {
  const payload: JwtPayload = {
    userId: user.id,
    email: user.email,
    role: user.role,
  };
  return jwt.sign(payload, JWT_SECRET, { expiresIn: JWT_EXPIRES_IN });
}

function sanitizeUser(row: any): User {
  const { password: _, ...user } = row;
  return user as User;
}

// ============================================================
// POST /api/v1/auth/register
// ============================================================

router.post('/register', async (req: Request, res: Response): Promise<void> => {
  try {
    const { username, email, password }: RegisterRequest = req.body;

    // --- Validation ---
    const errors: Record<string, string> = {};

    if (!username || typeof username !== 'string' || username.trim().length === 0) {
      errors.username = '用户名不能为空';
    } else if (username.trim().length < 3) {
      errors.username = '用户名长度不能少于3位';
    }

    if (!email || typeof email !== 'string') {
      errors.email = '邮箱不能为空';
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      errors.email = '邮箱格式不正确';
    }

    if (!password || typeof password !== 'string') {
      errors.password = '密码不能为空';
    } else if (password.length < 6) {
      errors.password = '密码长度不能少于6位';
    }

    if (Object.keys(errors).length > 0) {
      res.status(422).json({
        success: false,
        message: '参数验证失败',
        errors,
      });
      return;
    }

    const trimmedUsername = username.trim();
    const trimmedEmail = email.trim().toLowerCase();

    // --- Check existing user ---
    const existing = db
      .prepare('SELECT id FROM users WHERE email = ? OR username = ?')
      .get(trimmedEmail, trimmedUsername);

    if (existing) {
      res.status(400).json({
        success: false,
        message: '用户名或邮箱已存在',
      });
      return;
    }

    // --- Create user ---
    const hashedPassword = await bcrypt.hash(password, SALT_ROUNDS);
    const id = uuidv4();
    const now = new Date().toISOString();

    db.prepare(
      `INSERT INTO users (id, username, email, password, role, createdAt, updatedAt)
       VALUES (?, ?, ?, ?, ?, ?, ?)`
    ).run(id, trimmedUsername, trimmedEmail, hashedPassword, 'user', now, now);

    const user: User = {
      id,
      username: trimmedUsername,
      email: trimmedEmail,
      role: 'user',
      createdAt: now,
      updatedAt: now,
    };

    const token = generateToken(user);
    const response: AuthResponse = { user, token };

    res.status(201).json({
      success: true,
      data: response,
    });
  } catch (error) {
    console.error('[auth] register error:', error);
    res.status(500).json({
      success: false,
      message: '服务器内部错误',
    });
  }
});

// ============================================================
// POST /api/v1/auth/login
// ============================================================

router.post('/login', async (req: Request, res: Response): Promise<void> => {
  try {
    const { email, password }: LoginRequest = req.body;

    // --- Validation ---
    const errors: Record<string, string> = {};

    if (!email || typeof email !== 'string') {
      errors.email = '邮箱不能为空';
    }

    if (!password || typeof password !== 'string') {
      errors.password = '密码不能为空';
    }

    if (Object.keys(errors).length > 0) {
      res.status(422).json({
        success: false,
        message: '参数验证失败',
        errors,
      });
      return;
    }

    const normalizedEmail = email.trim().toLowerCase();

    // --- Find user ---
    const row = db.prepare('SELECT * FROM users WHERE email = ?').get(normalizedEmail) as any;

    if (!row) {
      res.status(404).json({
        success: false,
        message: '用户不存在',
      });
      return;
    }

    // --- Verify password ---
    const isMatch = await bcrypt.compare(password, row.password);

    if (!isMatch) {
      res.status(401).json({
        success: false,
        message: '密码错误',
      });
      return;
    }

    const user = sanitizeUser(row);
    const token = generateToken(user);
    const response: AuthResponse = { user, token };

    res.status(200).json({
      success: true,
      data: response,
    });
  } catch (error) {
    console.error('[auth] login error:', error);
    res.status(500).json({
      success: false,
      message: '服务器内部错误',
    });
  }
});

// ============================================================
// POST /api/v1/auth/logout
// ============================================================

router.post(
  '/logout',
  authMiddleware,
  (req: AuthMiddlewareRequest, res: Response): void => {
    // JWT is stateless; actual invalidation would require a token blacklist.
    // Client should discard the token upon receiving this response.
    res.status(200).json({
      success: true,
      message: '已登出',
    });
  }
);

// ============================================================
// GET /api/v1/auth/me
// ============================================================

router.get(
  '/me',
  authMiddleware,
  (req: AuthMiddlewareRequest, res: Response): void => {
    try {
      const row = db.prepare('SELECT * FROM users WHERE id = ?').get(req.user!.userId) as any;

      if (!row) {
        res.status(401).json({
          success: false,
          message: '用户不存在或已被删除',
        });
        return;
