import { Router, Request, Response } from 'express';
import { v4 as uuidv4 } from 'uuid';
import db from '../db';
import type {
  CreateProductRequest,
  UpdateProductRequest,
  Product,
  ProductListParams,
} from '../types';
import { authenticate, requireAdmin } from '../middleware/auth';

const router = Router();

// 将数据库行映射为 Product 对象
function mapProduct(row: any): Product {
  return {
    id: row.id,
    name: row.name,
    description: row.description,
    price: row.price,
    stock: row.stock,
    imageUrl: row.image_url ?? null,
    category: row.category,
    createdAt: row.created_at,
    updatedAt: row.updated_at,
  };
}

// ============================================================
// GET /api/v1/products - 获取商品列表
// ============================================================
router.get('/api/v1/products', (req: Request, res: Response) => {
  try {
    const {
      page = '1',
      limit = '20',
      category,
      search,
      sortBy = 'createdAt',
      order = 'desc',
    } = req.query as Record<string, string>;

    const pageNum = Math.max(1, parseInt(page, 10) || 1);
    const limitNum = Math.min(100, Math.max(1, parseInt(limit, 10) || 20));
    const offset = (pageNum - 1) * limitNum;

    // 允许的排序字段映射
    const sortColumnMap: Record<string, string> = {
      price: 'price',
      name: 'name',
      createdAt: 'created_at',
    };
    const sortColumn = sortColumnMap[sortBy] || 'created_at';
    const sortOrder = order === 'asc' ? 'ASC' : 'DESC';

    // 构建查询条件
    const conditions: string[] = [];
    const params: any[] = [];

    if (category) {
      conditions.push('category = ?');
      params.push(category);
    }

    if (search) {
      conditions.push('(name LIKE ? OR description LIKE ?)');
      params.push(`%${search}%`, `%${search}%`);
    }

    const whereClause =
      conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';

    // 查询总数
    const countSql = `SELECT COUNT(*) as total FROM products ${whereClause}`;
    const countRow = db.prepare(countSql).get(...params) as { total: number };
    const total = countRow ? countRow.total : 0;

    // 查询数据
    const dataSql = `SELECT * FROM products ${whereClause} ORDER BY ${sortColumn} ${sortOrder} LIMIT ? OFFSET ?`;
    const rows = db.prepare(dataSql).all(...params, limitNum, offset) as any[];

    const products: Product[] = rows.map(mapProduct);

    const totalPages = Math.ceil(total / limitNum);

    res.status(200).json({
      success: true,
      data: products,
      pagination: {
        page: pageNum,
        limit: limitNum,
        total,
        totalPages,
        hasNext: pageNum < totalPages,
        hasPrev: pageNum > 1,
      },
    });
  } catch (error) {
    console.error('获取商品列表失败:', error);
    res.status(500).json({
      success: false,
      message: '服务器内部错误',
    });
  }
});

// ============================================================
// GET /api/v1/products/:id - 获取商品详情
// ============================================================
router.get('/api/v1/products/:id', (req: Request, res: Response) => {
  try {
    const { id } = req.params;

    const row = db.prepare('SELECT * FROM products WHERE id = ?').get(id) as any;

    if (!row) {
      return res.status(404).json({
        success: false,
        message: '商品不存在',
      });
    }

    const product: Product = mapProduct(row);

    res.status(200).json({
      success: true,
      data: product,
    });
  } catch (error) {
    console.error('获取商品详情失败:', error);
    res.status(500).json({
      success: false,
      message: '服务器内部错误',
    });
  }
});

// ============================================================
// POST /api/v1/products - 创建商品 (管理员)
// ============================================================
router.post(
  '/api/v1/products',
  authenticate,
  requireAdmin,
  (req: Request, res: Response) => {
    try {
      const { name, description, price, stock, image_url, category } =
        req.body as CreateProductRequest;

      // 参数验证
      const errors: string[] = [];

      if (!name || typeof name !== 'string' || name.trim().length === 0) {
        errors.push('商品名称不能为空');
      }
      if (name && name.trim().length > 200) {
        errors.push('商品名称不能超过200个字符');
      }
      if (
        !description ||
        typeof description !== 'string' ||
        description.trim().length === 0
      ) {
        errors.push('商品描述不能为空');
      }
      if (price === undefined || price === null || typeof price !== 'number') {
        errors.push('商品价格不能为空且必须为数字');
      } else if (price < 0) {
        errors.push('商品价格不能为负数');
      }
      if (
        stock === undefined ||
        stock === null ||
        typeof stock !== 'number' ||
        !Number.isInteger(stock)
      ) {
        errors.push('商品库存不能为空且必须为整数');
      } else if (stock < 0) {
        errors.push('商品库存不能为负数');
      }
      if (!category || typeof category !== 'string' || category.trim().length === 0) {
        errors.push('商品分类不能为空');
      }

      if (errors.length > 0) {
        return res.status(400).json({
          success: false,
          message: '参数验证失败',
          errors,
        });
      }

      const id = uuidv4();
      const now = new Date().toISOString();
      const trimmedName = name.trim();
      const trimmedDescription = description.trim();
      const trimmedCategory = category.trim();
      const finalImageUrl = image_url?.trim() || null;

      db.prepare(
        `INSERT INTO products (id, name, description, price, stock, image_url, category, created_at, updated_at)
         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`
      ).run(
        id,
        trimmedName,
        trimmedDescription,
        price,
        stock,
        finalImageUrl,
        trimmedCategory,
        now,
        now
      );

      const product: Product = {
        id,
        name: trimmedName,
        description: trimmedDescription,
        price,
        stock,
        imageUrl: finalImageUrl,
        category: trimmedCategory,
        createdAt: now,
        updatedAt: now,
      };

      res.status(201).json({
        success: true,
        data: product,
      });
    } catch (error) {
      console.error('创建商品失败:', error);
      res.status(500).json({
        success: false,
        message: '服务器内部错误',
      });
    }
  }
);

// ============================================================
// PUT /api/v1/products/:id - 更新商品 (管理员)
// ============================================================
router.put(
  '/api/v1/products/:id',
  authenticate,
  requireAdmin,
  (req: Request, res: Response) => {
    try {
      const { id } = req.params;
      const { name, description, price, stock, image_url, category } =
        req.body as UpdateProductRequest;

      // 检查商品是否存在
      const existingRow = db
        .prepare('SELECT * FROM products WHERE id = ?')
        .get(id) as any;

      if (!existingRow) {
        return res.status(404).json({
          success: false,
          message: '商品不存在',
        });
      }

      // 参数验证
      const errors: string[] = [];

      if (name !== undefined) {
        if (typeof name !== 'string' || name.trim().length === 0) {
          errors.push('商品名称不能为空');
        } else if (name.trim().length > 200) {
          errors.push('商品名称不能超过200个字符');
        }
      }

      if (description !== undefined) {
        if (
          typeof description !== 'string' ||
          description.trim().length === 0
        ) {
          errors.push('商品描述不能为空');
        }
      }

      if (price !== undefined) {
        if (typeof price !== 'number') {
          errors.push('商品价格必须为数字');
        } else if (price < 0) {
          errors.push('商品价格不能为负数');
        }
      }

      if (stock !== undefined) {
        if (typeof stock !== 'number' || !Number.isInteger(stock)) {
          errors.push('商品库存必须为整数');
        } else if (stock < 0) {
          errors.push('商品库存不能为负数');
        }
      }

      if (category !== undefined) {
        if (typeof category !== 'string' || category.trim().length === 0) {
          errors.push('商品分类不能为空');
        }
      }

      if (errors.length > 0) {
        return res.status(400).json({
          success: false,
          message: '参数验证失败',
          errors,
        });
      }

      // 合并更新数据
      const updatedName =
        name !== undefined ? name.trim() : existingRow.name;
      const updatedDescription =
        description !== undefined ? description.trim() : existingRow.description;
      const updatedPrice =
        price !== undefined ? price : existingRow.price;
      const updatedStock =
        stock !== undefined ? stock : existingRow.stock;
      const updatedImageUrl =
        image_url !== undefined
          ? image_url?.trim() || null
          : existingRow.image_url;
      const updatedCategory =
        category !== undefined ? category.trim() : existingRow.category;
      const now = new Date().toISOString();

      db.prepare(
        `UPDATE products
         SET name = ?, description = ?, price = ?, stock = ?, image_url = ?, category = ?, updated_at = ?
         WHERE id = ?`
      ).run(
        updatedName,
        updatedDescription,
        updatedPrice,
        updatedStock,
        updatedImageUrl,
        updatedCategory,
        now,
        id
      );

      const product: Product = {
        id,
        name: updatedName,
        description: updatedDescription,
        price: updatedPrice,
        stock: updatedStock,
        imageUrl: updatedImageUrl,
        category: updatedCategory,
        createdAt: existingRow.created_at,
        updatedAt: now,
      };

      res.status(200).json({
        success: true,
        data: product,
      });
    } catch (error) {
      console.error('更新商品失败:', error);
      res.status(500).json({
        success: false,
        message: '服务器内部错误',
      });
    }
  }
);

// ============================================================
// DELETE /api/v1/products/:id - 删除商品 (管理员)
