import { Router, Request, Response } from 'express';
import { v4 as uuidv4 } from 'uuid';
import db from '../database';
import { authenticate } from '../middleware/auth';
import type { AddToCartRequest, UpdateCartItemRequest, CartItem, Cart } from '../types';

const router = Router();

// 所有购物车路由都需要认证
router.use(authenticate);

/**
 * GET /api/v1/cart
 * 获取当前用户的购物车内容
 */
router.get('/', (req: Request, res: Response) => {
  try {
    const userId = (req as any).user.id;

    const rows = db.prepare(`
      SELECT 
        ci.id,
        ci.product_id AS productId,
        p.name AS productName,
        p.price AS productPrice,
        p.image AS productImage,
        ci.quantity,
        (p.price * ci.quantity) AS subtotal
      FROM cart_items ci
      INNER JOIN products p ON ci.product_id = p.id
      WHERE ci.user_id = ?
    `).all(userId) as any[];

    const items: CartItem[] = rows.map(row => ({
      id: row.id,
      productId: row.productId,
      productName: row.productName,
      productPrice: row.productPrice,
      productImage: row.productImage,
      quantity: row.quantity,
      subtotal: row.subtotal,
    }));

    const totalAmount = items.reduce((sum, item) => sum + item.subtotal, 0);
    const itemCount = items.reduce((sum, item) => sum + item.quantity, 0);

    const cart: Cart = {
      items,
      totalAmount: Math.round(totalAmount * 100) / 100,
      itemCount,
    };

    res.json({ success: true, data: cart });
  } catch (error) {
    console.error('获取购物车失败:', error);
    res.status(500).json({ success: false, message: '获取购物车失败' });
  }
});

/**
 * POST /api/v1/cart/items
 * 添加商品到购物车
 */
router.post('/items', (req: Request, res: Response) => {
  try {
    const userId = (req as any).user.id;
    const { productId, quantity } = req.body as AddToCartRequest;

    // 参数验证
    if (!productId || typeof productId !== 'string') {
      return res.status(400).json({ success: false, message: '商品ID不能为空' });
    }

    if (!quantity || typeof quantity !== 'number' || quantity <= 0 || !Number.isInteger(quantity)) {
      return res.status(400).json({ success: false, message: '数量必须为正整数' });
    }

    // 检查商品是否存在
    const product = db.prepare('SELECT id, name, price, image, stock FROM products WHERE id = ?').get(productId) as any;

    if (!product) {
      return res.status(404).json({ success: false, message: '商品不存在' });
    }

    // 检查库存
    if (product.stock < quantity) {
      return res.status(400).json({ success: false, message: `库存不足，当前库存: ${product.stock}` });
    }

    // 检查购物车中是否已有该商品
    const existingItem = db.prepare(
      'SELECT id, quantity FROM cart_items WHERE user_id = ? AND product_id = ?'
    ).get(userId, productId) as any;

    let cartItem: any;

    if (existingItem) {
      const newQuantity = existingItem.quantity + quantity;

      // 检查合并后是否超过库存
      if (newQuantity > product.stock) {
        return res.status(400).json({
          success: false,
          message: `库存不足，购物车已有 ${existingItem.quantity} 件，当前库存: ${product.stock}`,
        });
      }

      db.prepare('UPDATE cart_items SET quantity = ?, updated_at = datetime("now") WHERE id = ?')
        .run(newQuantity, existingItem.id);

      cartItem = {
        id: existingItem.id,
        productId: product.id,
        productName: product.name,
        productPrice: product.price,
        productImage: product.image,
        quantity: newQuantity,
        subtotal: Math.round(product.price * newQuantity * 100) / 100,
      };
    } else {
      const id = uuidv4();

      db.prepare(
        'INSERT INTO cart_items (id, user_id, product_id, quantity, created_at, updated_at) VALUES (?, ?, ?, ?, datetime("now"), datetime("now"))'
      ).run(id, userId, productId, quantity);

      cartItem = {
        id,
        productId: product.id,
        productName: product.name,
        productPrice: product.price,
        productImage: product.image,
        quantity,
        subtotal: Math.round(product.price * quantity * 100) / 100,
      };
    }

    res.status(201).json({ success: true, data: cartItem as CartItem });
  } catch (error) {
    console.error('添加购物车失败:', error);
    res.status(500).json({ success: false, message: '添加购物车失败' });
  }
});

/**
 * PUT /api/v1/cart/items/:id
 * 更新购物车商品数量
 */
router.put('/items/:id', (req: Request, res: Response) => {
  try {
    const userId = (req as any).user.id;
    const itemId = req.params.id;
    const { quantity } = req.body as UpdateCartItemRequest;

    // 参数验证
    if (quantity === undefined || typeof quantity !== 'number' || quantity <= 0 || !Number.isInteger(quantity)) {
      return res.status(400).json({ success: false, message: '数量必须为正整数' });
    }

    // 查找购物车项
    const cartItem = db.prepare(
      'SELECT ci.id, ci.quantity, ci.product_id, p.name, p.price, p.image, p.stock FROM cart_items ci INNER JOIN products p ON ci.product_id = p.id WHERE ci.id = ? AND ci.user_id = ?'
    ).get(itemId, userId) as any;

    if (!cartItem) {
      return res.status(404).json({ success: false, message: '购物车项不存在' });
    }

    // 检查库存
    if (quantity > cartItem.stock) {
      return res.status(400).json({
        success: false,
        message: `库存不足，当前库存: ${cartItem.stock}`,
      });
    }

    // 更新数量
    db.prepare('UPDATE cart_items SET quantity = ?, updated_at = datetime("now") WHERE id = ?')
      .run(quantity, itemId);

    const updatedItem: CartItem = {
      id: cartItem.id,
      productId: cartItem.product_id,
      productName: cartItem.name,
      productPrice: cartItem.price,
      productImage: cartItem.image,
      quantity,
      subtotal: Math.round(cartItem.price * quantity * 100) / 100,
    };

    res.json({ success: true, data: updatedItem });
  } catch (error) {
    console.error('更新购物车失败:', error);
    res.status(500).json({ success: false, message: '更新购物车失败' });
  }
});

/**
 * DELETE /api/v1/cart/items/:id
 * 删除购物车中的单个商品
 */
router.delete('/items/:id', (req: Request, res: Response) => {
  try {
    const userId = (req as any).user.id;
    const itemId = req.params.id;

    // 查找购物车项
    const cartItem = db.prepare(
      'SELECT id FROM cart_items WHERE id = ? AND user_id = ?'
    ).get(itemId, userId) as any;

    if (!cartItem) {
      return res.status(404).json({ success: false, message: '购物车项不存在' });
    }

    db.prepare('DELETE FROM cart_items WHERE id = ? AND user_id = ?').run(itemId, userId);

    res.json({ success: true, message: '商品已从购物车移除' });
  } catch (error) {
    console.error('删除购物车项失败:', error);
    res.status(500).json({ success: false, message: '删除购物车项失败' });
  }
});

/**
 * DELETE /api/v1/cart
 * 清空购物车
 */
router.delete('/', (req: Request, res: Response) => {
