import { Router, Request, Response } from 'express';
import { v4 as uuidv4 } from 'uuid';
import db from '../db';
import { authMiddleware } from '../middleware/auth';
import { adminMiddleware } from '../middleware/admin';
import type {
  ShippingAddress,
  CreateOrderRequest,
  UpdateOrderStatusRequest,
  OrderItem,
  Order,
  OrderListParams,
  OrderStatus,
} from '../types';

const router = Router();

// All routes require authentication
router.use(authMiddleware);

// Valid status transitions for admin
const VALID_STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
  pending: ['confirmed', 'cancelled'],
  confirmed: ['processing', 'cancelled'],
  processing: ['shipped'],
  shipped: ['delivered'],
  delivered: [],
  cancelled: [],
};

/**
 * GET /api/v1/orders
 * Get order list with pagination and optional status filter
 */
router.get('/', (req: Request, res: Response) => {
  try {
    const userId = (req as any).userId;
    const userRole = (req as any).userRole;
    const { page = '1', limit = '10', status } = req.query as any;

    const pageNum = Math.max(1, parseInt(page, 10) || 1);
    const limitNum = Math.min(50, Math.max(1, parseInt(limit, 10) || 10));
    const offset = (pageNum - 1) * limitNum;

    let whereClause = '';
    const params: any[] = [];

    // Non-admin users can only see their own orders
    if (userRole !== 'admin') {
      whereClause = 'WHERE o.user_id = ?';
      params.push(userId);
    }

    if (status && ['pending', 'confirmed', 'processing', 'shipped', 'delivered', 'cancelled'].includes(status)) {
      whereClause = whereClause
        ? `${whereClause} AND o.status = ?`
        : 'WHERE o.status = ?';
      params.push(status);
    }

    // Count total orders
    const countRow = db
      .prepare(`SELECT COUNT(*) as total FROM orders o ${whereClause}`)
      .get(...params) as { total: number };

    const total = countRow.total;

    // Fetch orders with pagination
    const orders = db
      .prepare(
        `SELECT o.* FROM orders o ${whereClause} ORDER BY o.created_at DESC LIMIT ? OFFSET ?`
      )
      .all(...params, limitNum, offset) as any[];

    // Build full response with items for each order
    const ordersWithItems: Order[] = orders.map((order) => {
      const items = db
        .prepare('SELECT * FROM order_items WHERE order_id = ?')
        .all(order.id) as OrderItem[];

      return {
        id: order.id,
        userId: order.user_id,
        items,
        totalAmount: order.total_amount,
        status: order.status as OrderStatus,
        shippingAddress: JSON.parse(order.shipping_address),
        createdAt: order.created_at,
        updatedAt: order.updated_at,
      };
    });

    const totalPages = Math.ceil(total / limitNum);

    res.json({
      success: true,
      data: ordersWithItems,
      pagination: {
        page: pageNum,
        limit: limitNum,
        total,
        totalPages,
      },
    });
  } catch (error) {
    console.error('Get orders error:', error);
    res.status(500).json({ success: false, message: '获取订单列表失败' });
  }
});

/**
 * GET /api/v1/orders/:id
 * Get order detail by ID
 */
router.get('/:id', (req: Request, res: Response) => {
  try {
    const userId = (req as any).userId;
    const userRole = (req as any).userRole;
    const orderId = req.params.id;

    const order = db.prepare('SELECT * FROM orders WHERE id = ?').get(orderId) as any;

    if (!order) {
      return res.status(404).json({ success: false, message: '订单不存在' });
    }

    // Non-admin users can only access their own orders
    if (userRole !== 'admin' && order.user_id !== userId) {
      return res.status(403).json({ success: false, message: '无权访问他人订单' });
    }

    const items = db
      .prepare('SELECT * FROM order_items WHERE order_id = ?')
      .all(order.id) as OrderItem[];

    const orderData: Order = {
      id: order.id,
      userId: order.user_id,
      items,
      totalAmount: order.total_amount,
      status: order.status as OrderStatus,
      shippingAddress: JSON.parse(order.shipping_address),
      createdAt: order.created_at,
      updatedAt: order.updated_at,
    };

    res.json({ success: true, data: orderData });
  } catch (error) {
    console.error('Get order detail error:', error);
    res.status(500).json({ success: false, message: '获取订单详情失败' });
