});

/**
 * POST /api/v1/orders
 * Create order from cart
 */
router.post('/', (req: Request, res: Response) => {
  try {
    const userId = (req as any).userId;
    const { shippingAddress } = req.body as CreateOrderRequest;

    // Validate shipping address
    if (!shippingAddress) {
      return res.status(400).json({ success: false, message: '收货地址不能为空' });
    }

    const { fullName, phone, province, city, district, detail } = shippingAddress;
    if (!fullName || !phone || !province || !city || !district || !detail) {
      return res.status(400).json({ success: false, message: '收货地址信息不完整' });
    }

    // Get cart items
    const cartItems = db
      .prepare(
        `SELECT ci.*, p.name as product_name, p.image as product_image, p.price, p.stock
         FROM cart_items ci
         JOIN products p ON ci.product_id = p.id
         WHERE ci.user_id = ?`
      )
      .all(userId) as any[];

    if (cartItems.length === 0) {
      return res.status(400).json({ success: false, message: '购物车为空，无法创建订单' });
    }

    // Check stock availability for each item
    for (const item of cartItems) {
      if (item.stock < item.quantity) {
        return res.status(400).json({
          success: false,
          message: `商品 "${item.product_name}" 库存不足，当前库存: ${item.stock}`,
        });
      }
    }

    const orderId = uuidv4();
    const now = new Date().toISOString();

    // Calculate order items and total
    const orderItems: OrderItem[] = cartItems.map((item) => ({
      id: uuidv4(),
      productId: item.product_id,
      productName: item.product_name,
      productImage: item.product_image || null,
      quantity: item.quantity,
      price: item.price,
      subtotal: item.price * item.quantity,
    }));

    const totalAmount = orderItems.reduce((sum, item) => sum + item.subtotal, 0);

    // Use a transaction to ensure atomicity
    const createOrder = db.transaction(() => {
      // Insert order
      db.prepare(
        `INSERT INTO orders (id, user_id, total_amount, status, shipping_address, created_at, updated_at)
         VALUES (?, ?, ?, ?, ?, ?, ?)`
      ).run(orderId, userId, totalAmount, 'pending', JSON.stringify(shippingAddress), now, now);

      // Insert order items
      const insertItem = db.prepare(
        `INSERT INTO order_items (id, order_id, product_id, product_name, product_image, quantity, price, subtotal)
         VALUES (?, ?, ?, ?, ?, ?, ?, ?)`
      );

      for (const item of orderItems) {
        insertItem.run(
          item.id,
          orderId,
          item.productId,
          item.productName,
          item.productImage,
          item.quantity,
          item.price,
          item.subtotal
        );

        // Decrease stock
        db.prepare('UPDATE products SET stock = stock - ? WHERE id = ?').run(
          item.quantity,
          item.productId
        );
      }

      // Clear cart
      db.prepare('DELETE FROM cart_items WHERE user_id = ?').run(userId);
    });

    createOrder();

    const orderData: Order = {
      id: orderId,
      userId,
      items: orderItems,
      totalAmount,
      status: 'pending',
      shippingAddress,
      createdAt: now,
      updatedAt: now,
    };

    res.status(201).json({ success: true, data: orderData });
  } catch (error) {
    console.error('Create order error:', error);
    res.status(500).json({ success: false, message: '创建订单失败' });
  }
});

/**
 * PUT /api/v1/orders/:id/status
 * Update order status (admin only)
 */
router.put('/:id/status', adminMiddleware, (req: Request, res: Response) => {
  try {
    const orderId = req.params.id;
    const { status: newStatus } = req.body as UpdateOrderStatusRequest;

    // Validate status value
    const validStatuses: OrderStatus[] = [
      'pending',
      'confirmed',
      'processing',
      'shipped',
      'delivered',
      'cancelled',
    ];

    if (!newStatus || !validStatuses.includes(newStatus)) {
      return res.status(400).json({
        success: false,
        message: `无效的订单状态。有效状态: ${validStatuses.join(', ')}`,
      });
    }

    const order = db.prepare('SELECT * FROM orders WHERE id = ?').get(orderId) as any;

    if (!order) {
      return res.status(404).json({ success: false, message: '订单不存在' });
    }

    const currentStatus = order.status as OrderStatus;

    // Validate status transition
    const allowedNextStatuses = VALID_STATUS_TRANSITIONS[currentStatus];

    if (!allowedNextStatuses.includes(newStatus)) {
      return res.status(400).json({
        success: false,
        message: `无法将订单状态从 "${currentStatus}" 变更为 "${newStatus}"。允许的状态: ${allowedNextStatuses.join(', ') || '无'}`,
      });
    }

    // If cancelling, restore stock
    if (newStatus === 'cancelled') {
      const restoreStock = db.transaction(() => {
        const items = db
          .prepare('SELECT * FROM order_items WHERE order_id = ?')
          .all(orderId) as OrderItem[];

        for (const item of items) {
          db.prepare('UPDATE products SET stock = stock + ? WHERE id = ?').run(
            item.quantity,
            item.productId
          );
        }

        db.prepare(
          'UPDATE orders SET status = ?, updated_at = ? WHERE id = ?'
        ).run(newStatus, new Date().toISOString(), orderId);
      });

      restoreStock();
    } else {
      db.prepare(
        'UPDATE orders SET status = ?, updated_at = ? WHERE id = ?'
      ).run(newStatus, new Date().toISOString(), orderId);
    }

    // Fetch updated order
    const updatedOrder = db.prepare('SELECT * FROM orders WHERE id = ?').get(orderId) as any;
    const items = db
      .prepare('SELECT * FROM order_items WHERE order_id = ?')
      .all(orderId) as OrderItem[];

    const orderData: Order = {
      id: updatedOrder.id,
      userId: updatedOrder.user_id,
      items,
      totalAmount: updatedOrder.total_amount,
      status: updatedOrder.status as OrderStatus,
      shippingAddress: JSON.parse(updatedOrder.shipping_address),
      createdAt: updatedOrder.created_at,
      updatedAt: updatedOrder.updated_at,
    };

    res.json({ success: true, data: orderData });
  } catch (error) {
    console.error('Update order status error:', error);
    res.status(500).json({ success: false, message: '更新订单状态失败' });
  }
});

/**
 * DELETE /api/v1/orders/:id
 * Cancel order (user's own order or admin)
 */
router.delete('/:id', (req: Request, res: Response) => {
  try {
    const userId = (req as any).userId;
    const userRole = (req as any).userRole;
    const orderId = req.params.id;

    const order = db.prepare('SELECT * FROM orders WHERE id = ?').get(orderId) as any;

    if (!order) {
      return res.status(404).json({ success: false, message: '订单不存在' });
    }

    // Only the order owner or an admin can cancel
    if (userRole !== 'admin' && order.user_id !== userId) {
      return res.status(403).json({ success: false, message: '无权取消他人订单' });
    }

    // Only pending or confirmed orders can be cancelled
    if (!['pending', 'confirmed'].includes(order.status)) {
      return res.status(400).json({
        success: false,
        message: `当前订单状态为 "${order.status}"，无法取消。只有待付款和已确认的订单可以取消`,
      });
    }

    // Cancel order and restore stock in a transaction
    const cancelOrder = db.transaction(() => {
      const items = db
        .prepare('SELECT * FROM order_items WHERE order_id = ?')
        .all(orderId) as OrderItem[];

      for (const item of items) {
        db.prepare('UPDATE products SET stock = stock + ? WHERE id = ?').run(
          item.quantity,
          item.productId
        );
      }

      db.prepare(
        "UPDATE orders SET status = 'cancelled', updated_at = ? WHERE id = ?"
      ).run(new Date().toISOString(), orderId);
    });

    cancelOrder();

    res.json({ success: true, message: '订单已取消' });
  } catch (error) {
    console.error('Cancel order error:', error);
    res.status(500).json({ success: false, message: '取消订单失败' });
  }
});

export default router;

