import type { ApiServiceConfig, AuthApi, ProductsApi, CartApi, OrdersApi, ApiService } from '../types';
import type {
  ApiResponse,
  SuccessResponse,
  RegisterRequest,
  LoginRequest,
  AuthResponse,
  User,
  Product,
  ProductListParams,
  CreateProductRequest,
  UpdateProductRequest,
  Cart,
  CartItem,
  AddToCartRequest,
  UpdateCartItemRequest,
  Order,
  OrderListParams,
  CreateOrderRequest,
  UpdateOrderStatusRequest,
} from '../types';

// 默认配置
const defaultConfig: ApiServiceConfig = {
  baseURL: '/api/v1',
  timeout: 30000,
};

// 存储 token
let authToken: string | null = null;

// 设置认证令牌
export const setAuthToken = (token: string | null): void => {
  authToken = token;
  if (token) {
    localStorage.setItem('auth_token', token);
  } else {
    localStorage.removeItem('auth_token');
  }
};

// 获取认证令牌
export const getAuthToken = (): string | null => {
  if (!authToken) {
    authToken = localStorage.getItem('auth_token');
  }
  return authToken;
};

// HTTP 请求方法
const request = async <T>(
  endpoint: string,
  options: RequestInit = {},
  config: ApiServiceConfig = defaultConfig
): Promise<T> => {
  const url = `${config.baseURL}${endpoint}`;

  const headers: HeadersInit = {
    'Content-Type': 'application/json',
    ...options.headers,
  };

  // 自动注入 Authorization header
  const token = config.token || getAuthToken();
  if (token) {
    (headers as Record<string, string>)['Authorization'] = `Bearer ${token}`;
  }

  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), config.timeout);

  try {
    const response = await fetch(url, {
      ...options,
      headers,
      signal: controller.signal,
    });

    clearTimeout(timeoutId);

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw {
        status: response.status,
        message: errorData.message || `HTTP error ${response.status}`,
        data: errorData,
      };
    }

    const data = await response.json();
    return data as T;
  } catch (error: unknown) {
    clearTimeout(timeoutId);

    if (error instanceof Error && error.name === 'AbortError') {
      throw {
        status: 0,
        message: '请求超时，请稍后重试',
      };
    }

    throw error;
  }
};

// 通用 GET 请求
const get = <T>(endpoint: string, params?: Record<string, unknown>, config?: ApiServiceConfig): Promise<T> => {
  const searchParams = params ? `?${new URLSearchParams(params as Record<string, string>).toString()}` : '';
  return request<T>(`${endpoint}${searchParams}`, { method: 'GET' }, config);
};

// 通用 POST 请求
const post = <T>(endpoint: string, data?: unknown, config?: ApiServiceConfig): Promise<T> => {
  return request<T>(endpoint, {
    method: 'POST',
    body: data ? JSON.stringify(data) : undefined,
  }, config);
};

// 通用 PUT 请求
const put = <T>(endpoint: string, data?: unknown, config?: ApiServiceConfig): Promise<T> => {
  return request<T>(endpoint, {
    method: 'PUT',
    body: data ? JSON.stringify(data) : undefined,
  }, config);
};

// 通用 PATCH 请求
const patch = <T>(endpoint: string, data?: unknown, config?: ApiServiceConfig): Promise<T> => {
  return request<T>(endpoint, {
    method: 'PATCH',
    body: data ? JSON.stringify(data) : undefined,
  }, config);
};

// 通用 DELETE 请求
const del = <T>(endpoint: string, config?: ApiServiceConfig): Promise<T> => {
  return request<T>(endpoint, { method: 'DELETE' }, config);
};

// 创建 Auth API
const createAuthApi = (config?: ApiServiceConfig): AuthApi => ({
  register: (data: RegisterRequest) => 
    post<ApiResponse<AuthResponse>>('/auth/register', data, config),

  login: (data: LoginRequest) => 
    post<ApiResponse<AuthResponse>>('/auth/login', data, config),

  logout: () => 
    post<SuccessResponse>('/auth/logout', undefined, config),

  getMe: () => 
    get<ApiResponse<User>>('/auth/me', undefined, config),
});

// 创建 Products API
const createProductsApi = (config?: ApiServiceConfig): ProductsApi => ({
  getProducts: (params?: ProductListParams) => 
    get<ApiResponse<Product[]>>('/products', params as Record<string, unknown>, config),

  getProductById: (id: string) => 
    get<ApiResponse<Product>>(`/products/${id}`, undefined, config),

  createProduct: (data: CreateProductRequest) => 
    post<ApiResponse<Product>>('/products', data, config),

  updateProduct: (id: string, data: UpdateProductRequest) => 
    put<ApiResponse<Product>>(`/products/${id}`, data, config),

  deleteProduct: (id: string) => 
    del<SuccessResponse>(`/products/${id}`, config),
});

// 创建 Cart API
const createCartApi = (config?: ApiServiceConfig): CartApi => ({
  getCart: () => 
    get<ApiResponse<Cart>>('/cart', undefined, config),

  addToCart: (data: AddToCartRequest) => 
    post<ApiResponse<CartItem>>('/cart/items', data, config),

  updateCartItem: (id: string, data: UpdateCartItemRequest) => 
    put<ApiResponse<CartItem>>(`/cart/items/${id}`, data, config),

  removeCartItem: (id: string) => 
    del<SuccessResponse>(`/cart/items/${id}`, config),

  clearCart: () => 
    del<SuccessResponse>('/cart', config),
});

// 创建 Orders API
const createOrdersApi = (config?: ApiServiceConfig): OrdersApi => ({
  getOrders: (params?: OrderListParams) => 
    get<ApiResponse<Order[]>>('/orders', params as Record<string, unknown>, config),

  getOrderById: (id: string) => 
    get<ApiResponse<Order>>(`/orders/${id}`, undefined, config),

  createOrder: (data: CreateOrderRequest) => 
    post<ApiResponse<Order>>('/orders', data, config),

  updateOrderStatus: (id: string, data: UpdateOrderStatusRequest) => 
    patch<ApiResponse<Order>>(`/orders/${id}/status`, data, config),

  cancelOrder: (id: string) => 
    post<SuccessResponse>(`/orders/${id}/cancel`, undefined, config),
});

// 创建完整的 API 服务
export const createApiService = (config: ApiServiceConfig = defaultConfig): ApiService => {
  return {
    auth: createAuthApi(config),
    products: createProductsApi(config),
    cart: createCartApi(config),
    orders: createOrdersApi(config),
  };
};

// 默认导出的 API 服务实例
const apiService = createApiService();

// 导出独立的 API 实例
export const authApi = apiService.auth;
export const productsApi = apiService.products;
export const cartApi = apiService.cart;
export const ordersApi = apiService.orders;

// 导出工厂函数，用于创建自定义配置的 API 服务
export { createAuthApi, createProductsApi, createCartApi, createOrdersApi };

// 导出请求辅助方法
export const apiRequest = request;
export { get, post, put, patch, del };

// 导出配置管理
export const setApiConfig = (newConfig: Partial<ApiServiceConfig>): ApiServiceConfig => {
  return { ...defaultConfig, ...newConfig };
};

export default apiService;

