import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import type { LoginFormData, LoginPageState, LoginFormErrors } from '../types';

// API client
const apiClient = {
  async login(data: LoginFormData): Promise<{ token: string; user: { id: string; email: string; name: string } }> {
    const response = await fetch('/api/v1/auth/login', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(data),
    });

    if (!response.ok) {
      const error = await response.json().catch(() => ({ message: 'Login failed' }));
      throw new Error(error.message || 'Login failed');
    }

    return response.json();
  },
};

// Validation functions
const validateForm = (formData: LoginFormData): LoginFormErrors => {
  const errors: LoginFormErrors = {};

  if (!formData.email.trim()) {
    errors.email = 'Email is required';
  } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) {
    errors.email = 'Please enter a valid email address';
  }

  if (!formData.password) {
    errors.password = 'Password is required';
  } else if (formData.password.length < 6) {
    errors.password = 'Password must be at least 6 characters';
  }

  return errors;
};

const Login: React.FC = () => {
  const navigate = useNavigate();

  const [state, setState] = useState<LoginPageState>({
    formData: {
      email: '',
      password: '',
    },
    isLoading: false,
    error: null,
    rememberMe: false,
  });

  const [errors, setErrors] = useState<LoginFormErrors>({});
  const [touched, setTouched] = useState<{ email?: boolean; password?: boolean }>({});

  // Clear error when user starts typing
  useEffect(() => {
    if (state.error) {
      setState((prev) => ({ ...prev, error: null }));
    }
  }, [state.formData.email, state.formData.password]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type, checked } = e.target;

    if (type === 'checkbox') {
      setState((prev) => ({ ...prev, rememberMe: checked }));
    } else {
      setState((prev) => ({
        ...prev,
        formData: { ...prev.formData, [name]: value },
      }));
    }

    // Clear field error on change
    if (name in errors) {
      setErrors((prev) => ({ ...prev, [name]: undefined }));
    }
  };

  const handleBlur = (e: React.FocusEvent<HTMLInputElement>) => {
    const { name } = e.target;
    setTouched((prev) => ({ ...prev, [name]: true }));

    // Validate single field
    const fieldErrors = validateForm(state.formData);
    setErrors((prev) => ({ ...prev, [name]: fieldErrors[name as keyof LoginFormErrors] }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    // Validate all fields
    const formErrors = validateForm(state.formData);
    setErrors(formErrors);
    setTouched({ email: true, password: true });

    if (Object.keys(formErrors).length > 0) {
      return;
    }

    setState((prev) => ({ ...prev, isLoading: true, error: null }));

    try {
      const response = await apiClient.login(state.formData);

      // Store token
      if (state.rememberMe) {
        localStorage.setItem('authToken', response.token);
        localStorage.setItem('user', JSON.stringify(response.user));
      } else {
        sessionStorage.setItem('authToken', response.token);
        sessionStorage.setItem('user', JSON.stringify(response.user));
      }

      // Redirect to home or intended page
      navigate('/');
    } catch (err) {
      const message = err instanceof Error ? err.message : 'An unexpected error occurred';
      setState((prev) => ({ ...prev, error: message }));
    } finally {
      setState((prev) => ({ ...prev, isLoading: false }));
    }
  };

  const getFieldError = (field: 'email' | 'password'): string | undefined => {
    if (touched[field] && errors[field]) {
      return errors[field];
    }
    return undefined;
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col justify-center py-12 sm:px-6 lg:px-8">
      {/* Background decoration */}
      <div className="sm:mx-auto sm:w-full sm:max-w-md">
        <div className="flex justify-center">
          <div className="w-16 h-16 bg-indigo-600 rounded-xl flex items-center justify-center">
            <svg
              className="w-10 h-10 text-white"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"
              />
            </svg>
