const useProductList = (): ProductListPageState & ProductListActions => {
  const [state, setState] = useState<ProductListPageState>({
    products: [],
    pagination: null,
    filters: {},
    isLoading: false,
    error: null,
  });

  const fetchProducts = useCallback(async () => {
    setState(prev => ({ ...prev, isLoading: true, error: null }));

    try {
      const params = new URLSearchParams();

      if (state.filters.category) {
        params.append('category', state.filters.category);
      }
      if (state.filters.search) {
        params.append('search', state.filters.search);
      }
      if (state.filters.sortBy) {
        params.append('sortBy', state.filters.sortBy);
      }
      if (state.filters.order) {
        params.append('order', state.filters.order);
      }
      if (state.pagination?.page) {
        params.append('page', String(state.pagination.page));
      }
      if (state.pagination?.limit) {
        params.append('limit', String(state.pagination.limit));
      }

      const response = await apiClient.get(`/products?${params.toString()}`);

      setState(prev => ({
        ...prev,
        products: response.data.products || response.data,
        pagination: response.data.pagination || null,
        isLoading: false,
      }));
    } catch (error) {
      setState(prev => ({
        ...prev,
        error: error instanceof Error ? error.message : 'Failed to fetch products',
        isLoading: false,
      }));
    }
  }, [state.filters, state.pagination?.page, state.pagination?.limit]);

  useEffect(() => {
    fetchProducts();
  }, [fetchProducts]);

  const setPage = useCallback((page: number) => {
    setState(prev => ({
      ...prev,
      pagination: prev.pagination ? { ...prev.pagination, page } : { page, limit: 12, total: 0, totalPages: 0 },
    }));
  }, []);

  const setCategory = useCallback((category: string | undefined) => {
    setState(prev => ({
      ...prev,
      filters: { ...prev.filters, category },
      pagination: prev.pagination ? { ...prev.pagination, page: 1 } : null,
    }));
  }, []);

  const setSearch = useCallback((search: string) => {
    setState(prev => ({
      ...prev,
      filters: { ...prev.filters, search },
      pagination: prev.pagination ? { ...prev.pagination, page: 1 } : null,
    }));
  }, []);

  const setSortBy = useCallback((sortBy: string) => {
    setState(prev => ({
      ...prev,
      filters: { ...prev.filters, sortBy },
    }));
  }, []);

  const setOrder = useCallback((order: SortOrder) => {
    setState(prev => ({
      ...prev,
      filters: { ...prev.filters, order },
    }));
  }, []);

  const refresh = useCallback(() => {
    fetchProducts();
  }, [fetchProducts]);

  return {
    ...state,
    setPage,
    setCategory,
    setSearch,
    setSortBy,
    setOrder,
    refresh,
  };
};

