        ...prev,
        error: error instanceof Error ? error.message : 'An error occurred',
        isLoading: false,
      }));
    }
  }, []);

  useEffect(() => {
    fetchCart();
  }, [fetchCart]);

  const updateQuantity = useCallback(async (itemId: string, quantity: number) => {
    if (quantity < 1) return;

    const item = state.cart?.items.find(i => i.id === itemId);
    if (item && quantity > item.stock) {
      alert(`Only ${item.stock} items available in stock`);
      return;
    }

    try {
      const response = await fetch(`${API_BASE}/cart/items/${itemId}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        credentials: 'include',
        body: JSON.stringify({ quantity }),
      });

      if (!response.ok) {
        throw new Error('Failed to update quantity');
      }

      setState(prev => {
        if (!prev.cart) return prev;
        return {
          ...prev,
          cart: {
            ...prev.cart,
            items: prev.cart.items.map(item =>
              item.id === itemId ? { ...item, quantity } : item
            ),
          },
        };
      });
    } catch (error) {
      alert('Failed to update quantity. Please try again.');
    }
  }, [state.cart]);

  const removeItem = useCallback(async (itemId: string) => {
    if (!confirm('Are you sure you want to remove this item?')) return;

    try {
      const response = await fetch(`${API_BASE}/cart/items/${itemId}`, {
        method: 'DELETE',
        credentials: 'include',
      });

      if (!response.ok) {
        throw new Error('Failed to remove item');
      }

      setState(prev => {
        if (!prev.cart) return prev;
        return {
          ...prev,
          cart: {
            ...prev.cart,
            items: prev.cart.items.filter(item => item.id !== itemId),
          },
          selectedItemIds: prev.selectedItemIds.filter(id => id !== itemId),
        };
      });
    } catch (error) {
      alert('Failed to remove item. Please try again.');
    }
  }, []);

  const clearCart = useCallback(async () => {
    if (!confirm('Are you sure you want to clear your entire cart?')) return;

    try {
      const response = await fetch(`${API_BASE}/cart`, {
        method: 'DELETE',
        credentials: 'include',
      });

      if (!response.ok) {
        throw new Error('Failed to clear cart');
      }

      setState(prev => ({
        ...prev,
        cart: prev.cart ? { ...prev.cart, items: [] } : null,
        selectedItemIds: [],
      }));
    } catch (error) {
      alert('Failed to clear cart. Please try again.');
    }
  }, []);

  const toggleItemSelection = useCallback((itemId: string) => {
    setState(prev => ({
      ...prev,
      selectedItemIds: prev.selectedItemIds.includes(itemId)
        ? prev.selectedItemIds.filter(id => id !== itemId)
        : [...prev.selectedItemIds, itemId],
    }));
  }, []);

  const selectAll = useCallback(() => {
    setState(prev => ({
      ...prev,
      selectedItemIds: prev.cart?.items.map(item => item.id) || [],
    }));
  }, []);

  const deselectAll = useCallback(() => {
    setState(prev => ({
      ...prev,
      selectedItemIds: [],
    }));
  }, []);

  const checkout = useCallback(async (shippingAddress: ShippingAddress) => {
    if (state.selectedItemIds.length === 0) {
      alert('Please select at least one item to checkout');
      return;
    }

    try {
      setState(prev => ({ ...prev, isCheckingOut: true }));

      const response = await fetch(`${API_BASE}/orders`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        credentials: 'include',
        body: JSON.stringify({
          itemIds: state.selectedItemIds,
          shippingAddress,
        }),
      });

      if (!response.ok) {
        throw new Error('Failed to create order');
      }

      const order = await response.json();
      navigate(`/checkout/${order.id}`, { state: { order } });
    } catch (error) {
      alert('Failed to process checkout. Please try again.');
    } finally {
      setState(prev => ({ ...prev, isCheckingOut: false }));
    }
  }, [state.selectedItemIds, navigate]);

  const priceSummary = useMemo(() => {
    const selectedItems = state.cart?.items.filter(
      item => state.selectedItemIds.includes(item.id)
    ) || [];

    const subtotal = selectedItems.reduce(
      (sum, item) => sum + item.price * item.quantity,
      0
    );
    const shipping = subtotal > 100 ? 0 : 10;
    const tax = subtotal * 0.08;
    const total = subtotal + shipping + tax;

    return { subtotal, shipping, tax, total, itemCount: selectedItems.length };
  }, [state.cart, state.selectedItemIds]);

  const isAllSelected = useMemo(() => {
    return (
      state.cart?.items.length > 0 &&
      state.cart.items.every(item => state.selectedItemIds.includes(item.id))
    );
  }, [state.cart, state.selectedItemIds]);

  if (state.isLoading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto"></div>
          <p className="mt-4 text-gray-600">Loading your cart...</p>
        </div>
      </div>
    );
  }

  if (state.error) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center max-w-md mx-auto p-6 bg-white rounded-lg shadow-md">
          <AlertCircle className="h-12 w-12 text-red-500 mx-auto mb-4" />
          <h2 className="text-xl font-semibold text-gray-900 mb-2">Error</h2>
          <p className="text-gray-600 mb-4">{state.error}</p>
          <button
            onClick={fetchCart}
            className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
          >
            Try Again
          </button>
        </div>
      </div>
    );
  }

  if (!state.cart || state.cart.items.length === 0) {
    return (
      <div className="min-h-screen bg-gray-50">
        <div className="max-w-4xl mx-auto px-4 py-16">
          <div className="text-center">
            <ShoppingCart className="h-24 w-24 text-gray-300 mx-auto mb-6" />
            <h1 className="text-2xl font-bold text-gray-900 mb-4">Your Cart is Empty</h1>
            <p className="text-gray-600 mb-8">
              Looks like you haven't added anything to your cart yet.
            </p>
            <button
              onClick={() => navigate('/products')}
              className="px-6 py-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
            >
              Continue Shopping
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="max-w-6xl mx-auto px-4 py-8">
        <div className="flex items-center justify-between mb-8">
          <h1 className="text-3xl font-bold text-gray-900">Shopping Cart</h1>
          <button
            onClick={clearCart}
            className="text-red-600 hover:text-red-700 flex items-center gap-2"
          >
            <Trash2 className="h-5 w-5" />
            Clear Cart
          </button>
        </div>

        <div className="grid lg:grid-cols-3 gap-8">
          <div className="lg:col-span-2 space-y-4">
            <div className="bg-white rounded-lg shadow-sm p-4">
              <div className="flex items-center justify-between border-b pb-4 mb-4">
                <label className="flex items-center gap-3 cursor-pointer">
                  <input
                    type="checkbox"
                    checked={isAllSelected}
                    onChange={isAllSelected ? deselectAll : selectAll}
                    className="w-5 h-5 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                  />
                  <span className="font-medium text-gray-900">
                    {isAllSelected ? 'Deselect All' : 'Select All'}
                  </span>
                </label>
                <span className="text-gray-600">
                  {state.selectedItemIds.length} of {state.cart.items.length} items selected
                </span>
              </div>

              {state.cart.items.map(item => {
                const isSelected = state.selectedItemIds.includes(item.id);
                const isOutOfStock = item.quantity > item.stock;

                return (
                  <div
                    key={item.id}
                    className={`flex gap-4 p-4 rounded-lg border transition-colors ${
                      isSelected ? 'border-blue-500 bg-blue-50' : 'border-gray-200'
                    } ${isOutOfStock ? 'bg-red-50 border-red-200' : ''}`}
                  >
                    <input
                      type="checkbox"
                      checked={isSelected}
                      onChange={() => toggleItemSelection(item.id)}
                      className="mt-2 w-5 h-5 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                    />

                    <div className="w-24 h-24 bg-gray-200 rounded-lg overflow-hidden flex-shrink-0">
                      {item.image ? (
                        <img
                          src={item.image}
                          alt={item.name}
                          className="w-full h-full object-cover"
                        />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center">
                          <Package className="h-8 w-8 text-gray-400" />
                        </div>
                      )}
                    </div>

                    <div className="flex-1 min-w-0">
                      <h3 className="font-medium text-gray-900 truncate">{item.name}</h3>
                      <p className="text-lg font-semibold text-blue-600 mt-1">
                        ${item.price.toFixed(2)}
                      </p>

                      {isOutOfStock && (
                        <p className="text-sm text-red-600 mt-1">
                          Only {item.stock} available in stock
                        </p>
                      )}

                      <div className="flex items-center gap-4 mt-3">
                        <div className="flex items-center border rounded-lg">
                          <button
                            onClick={() => updateQuantity(item.id, item.quantity - 1)}
                            disabled={item.quantity <= 1}
                            className="p-2 hover:bg-gray-100 disabled:opacity-50 disabled:cursor-not-allowed"
                          >
                            <Minus className="h-4 w-4" />
                          </button>
                          <span className="px-4 font-medium min-w-[3rem] text-center">
                            {item.quantity}
                          </span>
                          <button
                            onClick={() => updateQuantity(item.id, item.quantity + 1)}
                            disabled={item.quantity >= item.stock}
                            className="p-2 hover:bg-gray-100 disabled:opacity-50 disabled:cursor-not-allowed"
                          >
                            <Plus className="h-4 w-4" />
                          </button>
                        </div>

                        <button
                          onClick={() => removeItem(item.id)}
                          className="p-2 text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                        >
                          <Trash2 className="h-5 w-5" />
                        </button>
                      </div>
                    </div>

                    <div className="text-right">
                      <p className="font-semibold text-gray-900">
                        ${(item.price * item.quantity).toFixed(2)}
                      </p>
                      {item.quantity > 1 && (
                        <p className="text-sm text-gray-500 mt-1">
                          ${item.price.toFixed(2)} each
                        </p>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>

          <div className="lg:col-span-1">
            <div className="bg-white rounded-lg shadow-sm p-6 sticky top-8">
              <h2 className="text-xl font-semibold text-gray-900 mb-6">Order Summary</h2>

              <div className="space-y-4 text-gray-700">
                <div className="flex justify-between">
                  <span>Subtotal ({priceSummary.itemCount} items)</span>
                  <span className="font-medium">${priceSummary.subtotal.toFixed(2)}</span>
                </div>

                <div className="flex justify-between">
                  <span>Shipping</span>
                  <span className="font-medium">
                    {priceSummary.shipping === 0 ? (
                      <span className="text-green-600">Free</span>
                    ) : (
                      `$${priceSummary.shipping.toFixed(2)}`
                    )}
                  </span>
                </div>

                {priceSummary.shipping > 0 && (
                  <p className="text-sm text-gray-500 -mt-2">
                    Free shipping on orders over $100
                  </p>
                )}

                <div className="flex justify-between">
                  <span>Tax (8%)</span>
                  <span className="font-medium">${priceSummary.tax.toFixed(2)}</span>
                </div>

                <div className="border-t pt-4 mt-4">
                  <div className="flex justify-between text-lg font-bold text-gray-900">
                    <span>Total</span>
                    <span>${priceSummary.total.toFixed(2)}</span>
                  </div>
                </div>
              </div>

              <button
                onClick={() => {
                  const address: ShippingAddress = {
                    id: 'new',
                    recipientName: '',
                    phone: '',
                    address: '',
                    city: '',
                    postalCode: '',
                  };
                  checkout(address);
                }}
                disabled={state.selectedItemIds.length === 0 || state.isCheckingOut}
                className={`w-full mt-6 py-3 rounded-lg font-semibold transition-colors ${
                  state.selectedItemIds.length === 0
                    ? 'bg-gray-300 text-gray-500 cursor-not-allowed'
                    : state.isCheckingOut
                    ? 'bg-blue-400 text-white cursor-wait'
                    : 'bg-blue-600 text-white hover:bg-blue-700'
                }`}
              >
                {state.isCheckingOut ? (
                  <span className="flex items-center justify-center gap-2">
                    <div className="animate-spin rounded-full h-5 w-5 border-2 border-white border-t-transparent"></div>
                    Processing...
                  </span>
                ) : (
                  `Checkout (${priceSummary.itemCount} items)`
                )}
              </button>

              {state.selectedItemIds.length === 0 && (
                <p className="text-sm text-gray-500 text-center mt-3">
                  Select items to proceed with checkout
                </p>
              )}

              <button
                onClick={() => navigate('/products')}
                className="w-full mt-4 py-2 text-blue-600 hover:bg-blue-50 rounded-lg font-medium transition-colors"
              >
                Continue Shopping
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CartPage;

import React, { useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import type { OrderListPageState, OrderListActions } from '../types';
import { orderApi } from '../services/api';
import { OrderStatus, Order, PaginationInfo } from '../types/models';
import LoadingSpinner from '../components/LoadingSpinner';
import ErrorMessage from '../components/ErrorMessage';
import Button from '../components/Button';
import Select from '../components/Select';

const statusConfig: Record<OrderStatus, { label: string; color: string; bgColor: string }> = {
  [OrderStatus.PENDING]: { label: '待支付', color: 'text-yellow-600', bgColor: 'bg-yellow-100' },
  [OrderStatus.PAID]: { label: '已支付', color: 'text-blue-600', bgColor: 'bg-blue-100' },
  [OrderStatus.SHIPPED]: { label: '已发货', color: 'text-purple-600', bgColor: 'bg-purple-100' },
  [OrderStatus.DELIVERED]: { label: '已收货', color: 'text-green-600', bgColor: 'bg-green-100' },
  [OrderStatus.CANCELLED]: { label: '已取消', color: 'text-gray-600', bgColor: 'bg-gray-100' },
  [OrderStatus.REFUNDED]: { label: '已退款', color: 'text-red-600', bgColor: 'bg-red-100' },
};

const OrderListPage: React.FC = () => {
  const navigate = useNavigate();

  // State
  const [state, setState] = React.useState<OrderListPageState>({
    orders: [],
    pagination: null,
    statusFilter: 'all',
    isLoading: false,
    error: null,
  });

  // Actions
  const setPage = useCallback((page: number) => {
    setState(prev => ({ ...prev, pagination: prev.pagination ? { ...prev.pagination, current: page } : null }));
  }, []);

  const setStatusFilter = useCallback((status: OrderStatus | 'all') => {
    setState(prev => ({ ...prev, statusFilter: status, pagination: prev.pagination ? { ...prev.pagination, current: 1 } : null }));
  }, []);

  const cancelOrder = useCallback(async (orderId: string) => {
    if (!window.confirm('确定要取消该订单吗？')) return;

    try {
      setState(prev => ({ ...prev, isLoading: true, error: null }));
      await orderApi.cancel(orderId);
      await refresh();
    } catch (error) {
      setState(prev => ({
        ...prev,
        isLoading: false,
        error: error instanceof Error ? error.message : '取消订单失败',
      }));
    }
  }, []);

  const refresh = useCallback(async () => {
    try {
      setState(prev => ({ ...prev, isLoading: true, error: null }));
      const currentPage = state.pagination?.current || 1;
      const response = await orderApi.getList({
        page: currentPage,
        limit: 10,
        status: state.statusFilter === 'all' ? undefined : state.statusFilter,
      });
      setState(prev => ({
        ...prev,
        orders: response.data,
        pagination: response.pagination,
        isLoading: false,
      }));
    } catch (error) {
      setState(prev => ({
        ...prev,
        isLoading: false,
        error: error instanceof Error ? error.message : '获取订单列表失败',
      }));
    }
  }, [state.pagination?.current, state.statusFilter]);

  // Fetch orders on mount and when page/status changes
  useEffect(() => {
    refresh();
  }, [state.pagination?.current, state.statusFilter]);

  const handleViewDetails = (orderId: string) => {
    navigate(`/orders/${orderId}`);
  };

  const formatPrice = (price: number) => {
    return `¥${price.toFixed(2)}`;
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleString('zh-CN', {
      year: 'numeric',
      month: '2-digit',
      day: '2-digit',
      hour: '2-digit',
      minute: '2-digit',
    });
  };

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="max-w-5xl mx-auto px-4">
        {/* Header */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-gray-900 mb-2">我的订单</h1>
          <p className="text-gray-600">查看和管理您的所有订单</p>
        </div>

        {/* Filter */}
        <div className="bg-white rounded-lg shadow-sm p-4 mb-6">
          <div className="flex items-center gap-4">
            <span className="text-gray-700 font-medium">筛选状态:</span>
            <Select
              value={state.statusFilter}
              onChange={(e) => setStatusFilter(e.target.value as OrderStatus | 'all')}
              className="w-40"
            >
              <option value="all">全部订单</option>
              {Object.values(OrderStatus).map(status => (
                <option key={status} value={status}>
                  {statusConfig[status].label}
                </option>
              ))}
            </Select>
            <Button
              variant="outline"
              size="sm"
              onClick={refresh}
              disabled={state.isLoading}
            >
              刷新
            </Button>
          </div>
        </div>

        {/* Error Message */}
        {state.error && (
          <ErrorMessage
            message={state.error}
            onClose={() => setState(prev => ({ ...prev, error: null }))}
            className="mb-6"
          />
        )}

        {/* Loading State */}
        {state.isLoading && state.orders.length === 0 && (
          <div className="flex justify-center items-center py-20">
            <LoadingSpinner size="lg" />
          </div>
        )}

        {/* Empty State */}
        {!state.isLoading && state.orders.length === 0 && !state.error && (
          <div className="bg-white rounded-lg shadow-sm p-12 text-center">
            <svg
              className="w-16 h-16 mx-auto text-gray-400 mb-4"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2"
              />
            </svg>
            <h3 className="text-lg font-medium text-gray-900 mb-2">暂无订单</h3>
            <p className="text-gray-500 mb-6">您还没有任何订单，快去选购商品吧</p>
            <Button variant="primary" onClick={() => navigate('/products')}>
              去购物
            </Button>
          </div>
        )}

        {/* Order List */}
        <div className="space-y-4">
          {state.orders.map(order => (
            <div
              key={order.id}
              className="bg-white rounded-lg shadow-sm overflow-hidden hover:shadow-md transition-shadow"
            >
              {/* Order Header */}
              <div className="flex items-center justify-between px-6 py-4 bg-gray-50 border-b border-gray-100">
                <div className="flex items-center gap-4">
                  <span className="text-sm text-gray-500">
                    订单号: <span className="font-mono text-gray-700">{order.orderNumber}</span>
                  </span>
                  <span className="text-sm text-gray-400">|</span>
                  <span className="text-sm text-gray-500">
                    {formatDate(order.createdAt)}
                  </span>
                </div>
                <span
                  className={`px-3 py-1 rounded-full text-sm font-medium ${
                    statusConfig[order.status].bgColor
                  } ${statusConfig[order.status].color}`}
                >
                  {statusConfig[order.status].label}
                </span>
              </div>

              {/* Order Items */}
              <div className="p-6">
                <div className="space-y-3 mb-4">
                  {order.items.slice(0, 3).map(item => (
                    <div key={item.id} className="flex items-center gap-4">
                      <img
                        src={item.image || 'https://via.placeholder.com/60'}
                        alt={item.name}
                        className="w-16 h-16 object-cover rounded-md bg-gray-100"
                      />
                      <div className="flex-1 min-w-0">
                        <p className="text-gray-900 font-medium truncate">{item.name}</p>
                        <p className="text-gray-500 text-sm">
                          {item.specification && (
                            <span className="mr-2">{item.specification}</span>
                          )}
                          x{item.quantity}
                        </p>
                      </div>
                      <span className="text-gray-900 font-medium">
                        {formatPrice(item.price * item.quantity)}
                      </span>
                    </div>
                  ))}
                  {order.items.length > 3 && (
                    <p className="text-sm text-gray-500 pl-20">
                      还有 {order.items.length - 3} 件商品...
                    </p>
                  )}
                </div>

                {/* Order Summary */}
                <div className="flex items-center justify-between pt-4 border-t border-gray-100">
                  <div className="text-gray-600">
                    共 <span className="font-medium text-gray-900">{order.items.length}</span> 件商品，
                    合计:{' '}
                    <span className="text-xl font-bold text-red-600">
                      {formatPrice(order.totalAmount)}
                    </span>
                  </div>
                  <div className="flex items-center gap-3">
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => handleViewDetails(order.id)}
                    >
                      查看详情
                    </Button>
                    {(order.status === OrderStatus.PENDING || order.status === OrderStatus.PAID) && (
                      <Button
                        variant="danger"
                        size="sm"
                        onClick={() => cancelOrder(order.id)}
                        disabled={state.isLoading}
                      >
                        取消订单
                      </Button>
                    )}
                    {order.status === OrderStatus.PAID && (
                      <Button
                        variant="primary"
                        size="sm"
                        onClick={() => navigate(`/orders/${order.id}/track`)}
                      >
                        查看物流
                      </Button>
                    )}
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Pagination */}
        {state.pagination && state.pagination.totalPages > 1 && (
          <div className="mt-8 flex items-center justify-center gap-2">
            <Button
              variant="outline"
              size="sm"
              disabled={state.pagination.current <= 1}
              onClick={() => setPage(state.pagination!.current - 1)}
            >
              上一页
            </Button>

            <div className="flex items-center gap-1">
              {Array.from({ length: state.pagination.totalPages }, (_, i) => i + 1)
                .filter(page => {
                  const current = state.pagination!.current;
                  return page === 1 || page === state.pagination!.totalPages || 
                         Math.abs(page - current) <= 1;
                })
                .map((page, index, array) => {
                  const prevPage = array[index - 1];
                  const showEllipsis = prevPage && page - prevPage > 1;

                  return (
                    <React.Fragment key={page}>
                      {showEllipsis && (
                        <span className="px-3 py-1 text-gray-400">...</span>
                      )}
                      <Button
                        variant={page === state.pagination!.current ? 'primary' : 'outline'}
                        size="sm"
                        onClick={() => setPage(page)}
                      >
                        {page}
                      </Button>
                    </React.Fragment>
                  );
                })}
            </div>

            <Button
              variant="outline"
              size="sm"
              disabled={state.pagination.current >= state.pagination.totalPages}
              onClick={() => setPage(state.pagination!.current + 1)}
            >
              下一页
            </Button>

            <span className="ml-4 text-sm text-gray-500">
              共 {state.pagination.total} 条记录
            </span>
          </div>
        )}
      </div>
    </div>
  );
};

