import { useState } from 'react';
import type { ProductCardProps, ProductCardState } from '../types';
import type { Product } from '../types';

export interface ProductCardProps {
  product: Product;
  onAddToCart: (productId: string) => void;
  onClick: (productId: string) => void;
  isInCart?: boolean;
  showAddToCartButton?: boolean;
}

export interface ProductCardState {
  isAddingToCart: boolean;
  imageLoaded: boolean;
  imageError: boolean;
}

const ProductCard: React.FC<ProductCardProps> = ({
  product,
  onAddToCart,
  onClick,
  isInCart = false,
  showAddToCartButton = true,
}) => {
  const [state, setState] = useState<ProductCardState>({
    isAddingToCart: false,
    imageLoaded: false,
    imageError: false,
  });

  const handleAddToCart = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (state.isAddingToCart || isInCart) return;

    setState((prev) => ({ ...prev, isAddingToCart: true }));

    try {
      await onAddToCart(product.id);
    } finally {
      setState((prev) => ({ ...prev, isAddingToCart: false }));
    }
  };

  const handleCardClick = () => {
    onClick(product.id);
  };

  const handleImageLoad = () => {
    setState((prev) => ({ ...prev, imageLoaded: true }));
  };

  const handleImageError = () => {
    setState((prev) => ({ ...prev, imageError: true }));
  };

  const formatPrice = (price: number): string => {
    return new Intl.NumberFormat('zh-CN', {
      style: 'currency',
      currency: 'CNY',
    }).format(price);
  };

  return (
    <div
      className="group relative bg-white rounded-xl shadow-sm hover:shadow-lg transition-all duration-300 overflow-hidden cursor-pointer"
      onClick={handleCardClick}
      role="button"
      tabIndex={0}
      onKeyDown={(e) => {
        if (e.key === 'Enter' || e.key === ' ') {
          e.preventDefault();
          handleCardClick();
        }
      }}
      aria-label={`查看商品: ${product.name}`}
    >
      {/* Image Container */}
      <div className="relative aspect-square bg-gray-100 overflow-hidden">
        {!state.imageLoaded && !state.imageError && (
          <div className="absolute inset-0 flex items-center justify-center">
            <div className="w-8 h-8 border-4 border-primary-200 border-t-primary-600 rounded-full animate-spin" />
          </div>
        )}

        {state.imageError ? (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-gray-200">
            <svg
              className="w-12 h-12 text-gray-400"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"
              />
            </svg>
            <span className="mt-2 text-sm text-gray-500">图片加载失败</span>
          </div>
        ) : (
          <img
            src={product.image}
            alt={product.name}
            className={`w-full h-full object-cover transition-transform duration-300 group-hover:scale-105 ${
              state.imageLoaded ? 'opacity-100' : 'opacity-0'
            }`}
            onLoad={handleImageLoad}
            onError={handleImageError}
          />
        )}

        {/* Discount Badge */}
        {product.discount && product.discount < 100 && (
          <div className="absolute top-2 left-2 bg-red-500 text-white text-xs font-bold px-2 py-1 rounded-md">
            -{product.discount}%
          </div>
        )}

        {/* Stock Badge */}
        {product.stock !== undefined && product.stock <= 5 && product.stock > 0 && (
          <div className="absolute top-2 right-2 bg-orange-500 text-white text-xs font-bold px-2 py-1 rounded-md">
            仅剩 {product.stock}
          </div>
        )}

        {/* Out of Stock Overlay */}
        {product.stock !== undefined && product.stock === 0 && (
          <div className="absolute inset-0 bg-black/50 flex items-center justify-center">
            <span className="text-white text-lg font-bold">缺货</span>
          </div>
        )}
      </div>

      {/* Content */}
      <div className="p-4">
        {/* Product Name */}
        <h3 className="text-sm font-medium text-gray-900 line-clamp-2 h-10 overflow-hidden group-hover:text-primary-600 transition-colors">
          {product.name}
        </h3>

        {/* Description */}
        {product.description && (
          <p className="mt-1 text-xs text-gray-500 line-clamp-1">
            {product.description}
          </p>
        )}

        {/* Price */}
        <div className="mt-3 flex items-baseline gap-2">
          <span className="text-xl font-bold text-red-500">
            {formatPrice(product.price)}
          </span>
          {product.originalPrice && product.originalPrice > product.price && (
            <span className="text-sm text-gray-400 line-through">
              {formatPrice(product.originalPrice)}
            </span>
          )}
        </div>

        {/* Rating */}
        {product.rating !== undefined && (
          <div className="mt-2 flex items-center gap-1">
            <div className="flex items-center">
              {[1, 2, 3, 4, 5].map((star) => (
                <svg
                  key={star}
                  className={`w-4 h-4 ${
                    star <= Math.round(product.rating!)
                      ? 'text-yellow-400'
                      : 'text-gray-300'
                  }`}
                  fill="currentColor"
                  viewBox="0 0 20 20"
                >
                  <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
                </svg>
              ))}
            </div>
            <span className="text-xs text-gray-500">({product.rating.toFixed(1)})</span>
            {product.salesCount !== undefined && (
              <span className="text-xs text-gray-400 ml-1">
                已售 {product.salesCount}
              </span>
            )}
          </div>
        )}

        {/* Add to Cart Button */}
        {showAddToCartButton && (
          <div className="mt-4">
            <button
              onClick={handleAddToCart}
              disabled={state.isAddingToCart || isInCart || product.stock === 0}
              className={`w-full py-2 px-4 rounded-lg font-medium text-sm transition-all duration-200 flex items-center justify-center gap-2 ${
                isInCart
                  ? 'bg-green-100 text-green-700 cursor-default'
                  : product.stock === 0
                  ? 'bg-gray-100 text-gray-400 cursor-not-allowed'
                  : 'bg-primary-600 text-white hover:bg-primary-700 active:bg-primary-800 disabled:opacity-50 disabled:cursor-not-allowed'
              }`}
              aria-label={
                isInCart
                  ? '已在购物车'
                  : product.stock === 0
                  ? '缺货'
                  : '加入购物车'
              }
            >
              {state.isAddingToCart ? (
                <>
                  <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                  <span>加入中...</span>
                </>
              ) : isInCart ? (
                <>
                  <svg
                    className="w-4 h-4"
                    fill="none"
                    stroke="currentColor"
                    viewBox="0 0 24 24"
                  >
                    <path
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      strokeWidth={2}
                      d="M5 13l4 4L19 7"
                    />
                  </svg>
                  <span>已加入</span>
                </>
              ) : product.stock === 0 ? (
                <span>缺货</span>
              ) : (
                <>
                  <svg
                    className="w-4 h-4"
                    fill="none"
                    stroke="currentColor"
                    viewBox="0 0 24 24"
                  >
                    <path
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      strokeWidth={2}
                      d="M3 3h2l.4 2M7 13h10l4-8H5.4M7 13L5.4 5M7 13l-2.293 2.293c-.63.63-.184 1.707.707 1.707H17m0 0a2 2 0 100 4 2 2 0 000-4zm-8 2a2 2 0 11-4 0 2 2 0 014 0z"
                    />
                  </svg>
                  <span>加入购物车</span>
                </>
              )}
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default ProductCard;

import { useState, useEffect, useCallback } from 'react';
import type { CartItemProps, CartItemState } from '../types';

export const CartItem = ({
  item,
  onUpdateQuantity,
  onRemove,
  isSelected = false,
  onSelect,
  isUpdating = false,
}: CartItemProps) => {
  const [state, setState] = useState<CartItemState>({
    isRemoving: false,
    localQuantity: item.quantity,
  });

  useEffect(() => {
    setState((prev) => ({ ...prev, localQuantity: item.quantity }));
  }, [item.quantity]);

  const handleQuantityChange = useCallback(
    (newQuantity: number) => {
      if (newQuantity < 1) return;
      if (newQuantity > item.stock) return;

      setState((prev) => ({ ...prev, localQuantity: newQuantity }));
      onUpdateQuantity(item.id, newQuantity);
    },
    [item.id, item.stock, onUpdateQuantity]
  );

  const handleIncrement = useCallback(() => {
    handleQuantityChange(state.localQuantity + 1);
  }, [handleQuantityChange, state.localQuantity]);

  const handleDecrement = useCallback(() => {
    handleQuantityChange(state.localQuantity - 1);
  }, [handleQuantityChange, state.localQuantity]);

  const handleRemove = useCallback(() => {
    setState((prev) => ({ ...prev, isRemoving: true }));
    setTimeout(() => {
      onRemove(item.id);
    }, 300);
  }, [item.id, onRemove]);

  const handleSelectChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      onSelect?.(item.id, e.target.checked);
    },
    [item.id, onSelect]
  );

  const subtotal = item.price * state.localQuantity;
  const originalPrice = item.originalPrice || item.price;
  const hasDiscount = originalPrice > item.price;
  const discount = hasDiscount
    ? Math.round(((originalPrice - item.price) / originalPrice) * 100)
    : 0;

  return (
    <div
      className={`
        relative bg-white rounded-xl p-4 md:p-6
        transition-all duration-300 ease-out
        ${state.isRemoving ? 'opacity-0 translate-x-full scale-95' : 'opacity-100 translate-x-0 scale-100'}
        ${isUpdating ? 'ring-2 ring-primary-200 bg-primary-50/30' : 'shadow-soft'}
        ${isSelected ? 'ring-2 ring-primary-500' : ''}
        hover:shadow-medium
      `}
    >
      {/* Selection Checkbox */}
      {onSelect && (
        <div className="absolute left-4 top-1/2 -translate-y-1/2 z-10">
          <label className="flex items-center cursor-pointer">
            <input
              type="checkbox"
              checked={isSelected}
              onChange={handleSelectChange}
              className="
                w-5 h-5 rounded-md border-2
                text-primary-600 bg-white
                focus:ring-2 focus:ring-primary-500 focus:ring-offset-2
                cursor-pointer
                transition-colors duration-200
                checked:bg-primary-600 checked:border-primary-600
              "
            />
          </label>
        </div>
      )}

      <div className={`flex gap-4 md:gap-6 ${onSelect ? 'pl-8' : ''}`}>
        {/* Product Image */}
        <div className="relative flex-shrink-0">
          <div className="w-24 h-24 md:w-28 md:h-28 rounded-lg overflow-hidden bg-gray-100">
            <img
              src={item.image}
              alt={item.name}
              className="w-full h-full object-cover"
              loading="lazy"
            />
          </div>
          {hasDiscount && (
            <div className="absolute -top-2 -left-2 bg-red-500 text-white text-xs font-bold px-2 py-1 rounded-full shadow-sm">
              -{discount}%
            </div>
          )}
          {item.stock <= 5 && item.stock > 0 && (
            <div className="absolute -bottom-1 -right-1 bg-orange-500 text-white text-xs font-medium px-2 py-0.5 rounded-full shadow-sm">
              仅剩{item.stock}
            </div>
          )}
        </div>

        {/* Product Info */}
        <div className="flex-1 min-w-0">
          <div className="flex flex-col md:flex-row md:items-start md:justify-between gap-2 md:gap-4">
            <div className="flex-1 min-w-0">
              {/* Product Name */}
              <h3 className="text-base md:text-lg font-semibold text-gray-900 line-clamp-2 mb-1">
                {item.name}
              </h3>

              {/* Product Description/Variant */}
              {item.variant && (
                <p className="text-sm text-gray-500 mb-2">{item.variant}</p>
              )}

              {/* Product Specs */}
              {item.specs && (
                <div className="flex flex-wrap gap-2 mb-2">
                  {item.specs.map((spec, index) => (
                    <span
                      key={index}
                      className="text-xs bg-gray-100 text-gray-600 px-2 py-1 rounded"
                    >
                      {spec}
                    </span>
                  ))}
                </div>
              )}

              {/* Price Section */}
              <div className="flex items-center gap-2 mt-2">
                <span className="text-lg md:text-xl font-bold text-primary-600">
                  ¥{item.price.toFixed(2)}
                </span>
                {hasDiscount && (
                  <span className="text-sm text-gray-400 line-through">
                    ¥{originalPrice.toFixed(2)}
                  </span>
                )}
              </div>
            </div>

            {/* Subtotal */}
            <div className="text-right">
              <p className="text-xs text-gray-500 mb-1">小计</p>
              <p className="text-xl md:text-2xl font-bold text-red-600">
                ¥{subtotal.toFixed(2)}
              </p>
              {hasDiscount && (
                <p className="text-xs text-green-600 mt-1">
                  节省 ¥{((originalPrice - item.price) * state.localQuantity).toFixed(2)}
                </p>
              )}
            </div>
          </div>

          {/* Quantity & Actions Row */}
          <div className="flex items-center justify-between mt-4">
            {/* Quantity Selector */}
            <div className="flex items-center gap-2">
              <span className="text-sm text-gray-500">数量</span>
              <div
                className={`
                  flex items-center border-2 rounded-lg overflow-hidden
                  transition-all duration-200
                  ${isUpdating ? 'border-primary-300 bg-primary-50' : 'border-gray-200 hover:border-gray-300'}
                `}
              >
                <button
                  onClick={handleDecrement}
                  disabled={state.localQuantity <= 1 || isUpdating}
                  className="
                    w-8 h-8 md:w-9 md:h-9 flex items-center justify-center
                    text-gray-600 hover:bg-gray-100
                    disabled:opacity-40 disabled:cursor-not-allowed
                    transition-colors duration-200
                  "
                  aria-label="减少数量"
                >
                  <svg
                    className="w-4 h-4"
                    fill="none"
                    stroke="currentColor"
                    viewBox="0 0 24 24"
                  >
                    <path
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      strokeWidth={2}
                      d="M20 12H4"
                    />
                  </svg>
                </button>

                <input
                  type="number"
                  value={state.localQuantity}
                  onChange={(e) => {
                    const value = parseInt(e.target.value, 10);
                    if (!isNaN(value)) {
                      handleQuantityChange(value);
                    }
                  }}
                  disabled={isUpdating}
                  className="
                    w-12 md:w-14 h-8 md:h-9 text-center
                    border-x-2 border-gray-200
                    text-sm md:text-base font-medium text-gray-900
                    focus:outline-none focus:bg-primary-50
                    disabled:bg-gray-100 disabled:cursor-not-allowed
                    [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none
                  "
                  min={1}
                  max={item.stock}
                />

                <button
                  onClick={handleIncrement}
                  disabled={state.localQuantity >= item.stock || isUpdating}
                  className="
                    w-8 h-8 md:w-9 md:h-9 flex items-center justify-center
                    text-gray-600 hover:bg-gray-100
                    disabled:opacity-40 disabled:cursor-not-allowed
                    transition-colors duration-200
                  "
                  aria-label="增加数量"
                >
                  <svg
                    className="w-4 h-4"
                    fill="none"
                    stroke="currentColor"
                    viewBox="0 0 24 24"
                  >
                    <path
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      strokeWidth={2}
                      d="M12 4v16m8-8H4"
                    />
