              )}
            </div>

            {/* Action Buttons */}
            <div className="flex items-center gap-2">
              {/* Favorite Button (Optional) */}
              <button
                className="
                  hidden md:flex items-center gap-1 px-3 py-1.5
                  text-sm text-gray-500 hover:text-red-500
                  border border-gray-200 rounded-lg
                  hover:border-red-300
                  transition-colors duration-200
                "
                aria-label="移入收藏夹"
              >
                <svg
                  className="w-4 h-4"
                  fill="none"
                  stroke="currentColor"
                  viewBox="0 0 24 24"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={1.5}
                    d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"
                  />
                </svg>
                <span>收藏</span>
              </button>

              {/* Remove Button */}
              <button
                onClick={handleRemove}
                disabled={state.isRemoving}
                className="
                  flex items-center gap-1 px-3 py-1.5
                  text-sm text-gray-500 hover:text-red-600
                  border border-gray-200 rounded-lg
                  hover:border-red-300 hover:bg-red-50
                  disabled:opacity-50 disabled:cursor-not-allowed
                  transition-all duration-200
                "
                aria-label="删除商品"
              >
                <svg
                  className="w-4 h-4"
                  fill="none"
                  stroke="currentColor"
                  viewBox="0 0 24 24"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={1.5}
                    d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"
                  />
                </svg>
                <span className="hidden sm:inline">删除</span>
              </button>
            </div>
          </div>

          {/* Loading Indicator */}
          {isUpdating && (
            <div className="absolute inset-0 flex items-center justify-center bg-white/60 rounded-xl">
              <div className="flex items-center gap-2 text-primary-600">
                <svg
                  className="w-5 h-5 animate-spin"
                  fill="none"
                  viewBox="0 0 24 24"
                >
                  <circle
                    className="opacity-25"
                    cx="12"
                    cy="12"
                    r="10"
                    stroke="currentColor"
                    strokeWidth="4"
                  />
                  <path
                    className="opacity-75"
                    fill="currentColor"
                    d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
                  />
                </svg>
                <span className="text-sm font-medium">更新中...</span>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

