import React from 'react';
import type { ButtonProps, ButtonStyleConfig, ButtonVariant, ButtonSize } from '../types';

export type { ButtonVariant, ButtonSize };
export type { ButtonProps, ButtonStyleConfig };

const buttonStyleConfig: ButtonStyleConfig = {
  baseClasses:
    'inline-flex items-center justify-center font-medium rounded-lg transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2 disabled:cursor-not-allowed',
  variantClasses: {
    primary:
      'bg-blue-600 text-white hover:bg-blue-700 active:bg-blue-800 focus:ring-blue-500 shadow-sm hover:shadow-md',
    secondary:
      'bg-gray-100 text-gray-900 hover:bg-gray-200 active:bg-gray-300 focus:ring-gray-500 dark:bg-gray-700 dark:text-gray-100 dark:hover:bg-gray-600',
    danger:
      'bg-red-600 text-white hover:bg-red-700 active:bg-red-800 focus:ring-red-500 shadow-sm hover:shadow-md',
    ghost:
      'bg-transparent text-gray-700 hover:bg-gray-100 active:bg-gray-200 focus:ring-gray-500 dark:text-gray-200 dark:hover:bg-gray-800',
    outline:
      'bg-transparent border-2 border-gray-300 text-gray-700 hover:bg-gray-50 active:bg-gray-100 focus:ring-gray-500 dark:border-gray-600 dark:text-gray-200 dark:hover:bg-gray-800',
  },
  sizeClasses: {
    sm: 'px-3 py-1.5 text-sm gap-1.5',
    md: 'px-4 py-2 text-base gap-2',
    lg: 'px-6 py-3 text-lg gap-2.5',
  },
  disabledClasses:
    'opacity-50 cursor-not-allowed pointer-events-none',
  loadingClasses: 'relative cursor-wait',
};

const getButtonClasses = (
  variant: ButtonVariant,
  size: ButtonSize,
  isLoading: boolean,
  disabled: boolean,
  fullWidth: boolean
): string => {
  const classes = [
    buttonStyleConfig.baseClasses,
    buttonStyleConfig.variantClasses[variant],
    buttonStyleConfig.sizeClasses[size],
    fullWidth ? 'w-full' : '',
    isLoading ? buttonStyleConfig.loadingClasses : '',
    disabled || isLoading ? buttonStyleConfig.disabledClasses : '',
  ]
    .filter(Boolean)
    .join(' ');

  return classes;
};

const LoadingSpinner: React.FC<{ size: ButtonSize }> = ({ size }) => {
  const spinnerSizeClasses = {
    sm: 'w-3.5 h-3.5',
    md: 'w-4 h-4',
    lg: 'w-5 h-5',
  };

  return (
    <svg
      className={`animate-spin ${spinnerSizeClasses[size]}`}
      xmlns="http://www.w3.org/2000/svg"
      fill="none"
      viewBox="0 0 24 24"
    >
      <circle
        className="opacity-25"
        cx="12"
        cy="12"
        r="10"
        stroke="currentColor"
        strokeWidth="4"
      />
      <path
        className="opacity-75"
        fill="currentColor"
        d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
      />
    </svg>
  );
};

export const Button: React.FC<ButtonProps> = ({
  children,
  variant = 'primary',
  size = 'md',
  isLoading = false,
  disabled = false,
  fullWidth = false,
  type = 'button',
  icon,
  iconPosition = 'left',
  onClick,
  className = '',
  ariaLabel,
}) => {
  const buttonClasses = getButtonClasses(
    variant,
    size,
    isLoading,
    disabled,
    fullWidth
  );

  const handleClick = (event: React.MouseEvent<HTMLButtonElement>) => {
    if (isLoading || disabled) {
      event.preventDefault();
      return;
    }
    onClick?.(event);
  };

  const renderContent = () => {
    if (!icon) {
      return (
        <span className={isLoading ? 'opacity-0' : ''}>{children}</span>
      );
    }

    const iconElement = (
      <span className="flex-shrink-0">
        {icon}
      </span>
    );

    return (
      <>
        {iconPosition === 'left' && iconElement}
        <span className={isLoading ? 'opacity-0' : ''}>{children}</span>
        {iconPosition === 'right' && iconElement}
      </>
    );
  };

  return (
    <button
      type={type}
      className={`${buttonClasses} ${className}`}
      onClick={handleClick}
      disabled={disabled || isLoading}
      aria-label={ariaLabel}
      aria-busy={isLoading}
    >
      {isLoading && (
        <span className="absolute inset-0 flex items-center justify-center">
          <LoadingSpinner size={size} />
        </span>
      )}
      {renderContent()}
    </button>
  );
};

Button.displayName = 'Button';

export default Button;

import React, { useState, useCallback } from 'react';
import type { InputProps, InputStyleConfig, InputState, InputType } from '../types';

// Default style configuration
const defaultStyleConfig: InputStyleConfig = {
  baseClasses: 'w-full px-4 py-2.5 text-sm border rounded-lg transition-all duration-200 outline-none bg-white dark:bg-gray-800 text-gray-900 dark:text-white placeholder-gray-400 dark:placeholder-gray-500',
  errorClasses: 'border-red-500 focus:border-red-500 focus:ring-2 focus:ring-red-200 dark:focus:ring-red-900',
  disabledClasses: 'bg-gray-100 dark:bg-gray-700 cursor-not-allowed opacity-60',
  iconLeftPadding: 'pl-10',
  iconRightPadding: 'pr-10',
};

// Password visibility icons
const EyeIcon = () => (
  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
  </svg>
);

const EyeSlashIcon = () => (
  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l3.59 3.59m0 0A9.953 9.953 0 0112 5c4.478 0 8.268 2.943 9.543 7a10.025 10.025 0 01-4.132 5.411m0 0L21 21" />
  </svg>
);

const ExclamationIcon = () => (
  <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20">
    <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
  </svg>
);

export const Input: React.FC<InputProps> = ({
  id,
  name,
  type = 'text',
  label,
  placeholder,
  value,
  onChange,
  onBlur,
  error,
  hint,
  icon,
  iconPosition = 'left',
  disabled = false,
  required = false,
  readOnly = false,
  autoFocus = false,
  maxLength,
  min,
  max,
  step,
  className = '',
  ariaLabel,
  autoComplete,
}) => {
  const [state, setState] = useState<InputState>({
    isFocused: false,
    hasValue: Boolean(value),
    isPasswordVisible: false,
  });

  const [touched, setTouched] = useState(false);

  // Update hasValue when value changes
  React.useEffect(() => {
    setState(prev => ({ ...prev, hasValue: Boolean(value) }));
  }, [value]);

  const handleFocus = useCallback(() => {
    setState(prev => ({ ...prev, isFocused: true }));
  }, []);

  const handleBlur = useCallback((e: React.FocusEvent<HTMLInputElement>) => {
    setState(prev => ({ ...prev, isFocused: false }));
    setTouched(true);
    onBlur?.(e);
  }, [onBlur]);

  const togglePasswordVisibility = useCallback(() => {
    setState(prev => ({ ...prev, isPasswordVisible: !prev.isPasswordVisible }));
  }, []);

  // Determine actual input type
  const getInputType = (): InputType => {
    if (type === 'password') {
      return state.isPasswordVisible ? 'text' : 'password';
    }
    return type;
  };

  // Build input classes
  const getInputClasses = (): string => {
    const classes: string[] = [defaultStyleConfig.baseClasses];

    // Add icon padding
    if (icon && iconPosition === 'left') {
      classes.push(defaultStyleConfig.iconLeftPadding);
    } else if (icon && iconPosition === 'right') {
      classes.push(defaultStyleConfig.iconRightPadding);
    } else if (type === 'password') {
      classes.push(defaultStyleConfig.iconRightPadding);
    }

    // Error state
    if (error) {
      classes.push(defaultStyleConfig.errorClasses);
    } else if (!disabled && !readOnly) {
      classes.push('border-gray-300 dark:border-gray-600 focus:border-blue-500 focus:ring-2 focus:ring-blue-200 dark:focus:ring-blue-900');
    }

    // Disabled state
    if (disabled) {
      classes.push(defaultStyleConfig.disabledClasses);
    }

    // Read only state
    if (readOnly) {
      classes.push('cursor-default bg-gray-50 dark:bg-gray-900');
    }

    // Merge custom className
    if (className) {
      classes.push(className);
    }

    return classes.join(' ');
  };

  // Build label classes
  const getLabelClasses = (): string => {
    const classes: string[] = ['block text-sm font-medium mb-1.5'];

    if (error) {
      classes.push('text-red-600 dark:text-red-400');
    } else if (state.isFocused) {
      classes.push('text-blue-600 dark:text-blue-400');
    } else {
      classes.push('text-gray-700 dark:text-gray-300');
    }

    return classes.join(' ');
  };

  const inputId = id || name;
  const showError = touched && error;
  const hasError = Boolean(error);

  return (
    <div className="w-full">
      {/* Label */}
      {label && (
        <label htmlFor={inputId} className={getLabelClasses()}>
          {label}
          {required && <span className="text-red-500 ml-1">*</span>}
        </label>
      )}

      {/* Input wrapper */}
      <div className="relative">
        {/* Left Icon */}
        {icon && iconPosition === 'left' && (
          <div className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 dark:text-gray-500 pointer-events-none">
            {icon}
          </div>
        )}

        {/* Input */}
        <input
          id={inputId}
          name={name}
          type={getInputType()}
          placeholder={placeholder}
          value={value}
          onChange={onChange}
          onFocus={handleFocus}
          onBlur={handleBlur}
          disabled={disabled}
          required={required}
          readOnly={readOnly}
          autoFocus={autoFocus}
          maxLength={maxLength}
          min={min}
          max={max}
          step={step}
          className={getInputClasses()}
          autoComplete={autoComplete}
          aria-label={ariaLabel || label || name}
          aria-invalid={hasError}
          aria-describedby={
            [
              error ? `${inputId}-error` : null,
              hint ? `${inputId}-hint` : null,
            ].filter(Boolean).join(' ') || undefined
          }
        />

        {/* Password visibility toggle */}
        {type === 'password' && !disabled && !readOnly && (
          <button
            type="button"
            onClick={togglePasswordVisibility}
            className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 focus:outline-none focus:text-gray-600 dark:focus:text-gray-300 transition-colors"
            aria-label={state.isPasswordVisible ? 'Hide password' : 'Show password'}
          >
            {state.isPasswordVisible ? <EyeSlashIcon /> : <EyeIcon />}
          </button>
        )}

        {/* Error Icon */}
        {showError && type !== 'password' && (
          <div className="absolute right-3 top-1/2 -translate-y-1/2 text-red-500 pointer-events-none">
            <ExclamationIcon />
          </div>
        )}

        {/* Right Icon (non-password) */}
        {icon && iconPosition === 'right' && type !== 'password' && (
          <div className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 dark:text-gray-500 pointer-events-none">
            {icon}
          </div>
        )}
      </div>

      {/* Error message */}
      {showError && (
        <p id={`${inputId}-error`} className="mt-1.5 text-sm text-red-600 dark:text-red-400 flex items-center gap-1">
          {error}
        </p>
      )}

      {/* Hint text */}
      {hint && !showError && (
        <p id={`${inputId}-hint`} className="mt-1.5 text-sm text-gray-500 dark:text-gray-400">
          {hint}
        </p>
      )}

      {/* Character count */}
      {maxLength && (
        <p className="mt-1 text-xs text-gray-400 dark:text-gray-500 text-right">
          {String(value).length} / {maxLength}
        </p>
      )}
    </div>
  );
};

export default Input;

// ============================================================
// 电商平台 - API 契约分组
// ============================================================
// 本文件定义了电商平台所有 API 接口的契约规范
// 版本: 1.0.0
// Base URL: /api/v1
// Authentication: Bearer Token (JWT)
// Content-Type: application/json
// ============================================================

// [COMMON]
// 通用 API 描述和认证信息
// - Base URL: /api/v1
// - Authentication: Bearer Token (JWT)
// - 通用错误码: 400 (Bad Request), 401 (Unauthorized), 403 (Forbidden), 404 (Not Found), 500 (Server Error)
// - 通用分页参数: page (number), limit (number)
// - 通用响应格式: { data: T, message?: string, pagination?: PaginationInfo }

shared schemas:
- ApiError: { code: string, message: string, details?: any }
- SuccessResponse: { success: true, message: string }
- PaginationInfo: { page: number, limit: number, total: number, totalPages: number }
- IdParam: { id: string }
- EmptyRequest: {}

// ============================================================
// 服务端文件 - API 路由定义
// ============================================================

// [FILE: server/database/db.ts]
// 数据库初始化与类型定义
// 负责 SQLite 数据库的连接、初始化表结构
// 数据库表结构:
//   - users: id, username, email, password_hash, created_at, updated_at
//   - products: id, name, description, price, stock, image_url, category, created_at, updated_at
//   - cart_items: id, user_id, product_id, quantity, created_at, updated_at
//   - orders: id, user_id, total_amount, status, shipping_address, created_at, updated_at
//   - order_items: id, order_id, product_id, quantity, price, created_at

// [FILE: server/index.ts]
// 后端入口文件
// Express 应用配置与中间件
// - CORS 配置
// - JSON body parser
// - JWT 认证中间件
// - 路由挂载: /api/v1/auth, /api/v1/products, /api/v1/cart, /api/v1/orders
// - 错误处理中间件
// - 服务器监听端口: 3000

// [FILE: server/routes/auth.ts]
// 认证相关 API
// - POST /api/v1/auth/register - 用户注册
//   Request: { username: string, email: string, password: string }
//   Response 201: { success: true, data: { user: User, token: string } }
//   Error: 400 (用户名或邮箱已存在), 422 (参数验证失败)
//
// - POST /api/v1/auth/login - 用户登录
//   Request: { email: string, password: string }
//   Response 200: { success: true, data: { user: User, token: string } }
//   Error: 401 (密码错误), 404 (用户不存在)
//
// - POST /api/v1/auth/logout - 用户登出
//   Headers: Authorization: Bearer <token>
//   Response 200: { success: true, message: "已登出" }
//
// - GET /api/v1/auth/me - 获取当前用户信息
//   Headers: Authorization: Bearer <token>
//   Response 200: { success: true, data: User }
//   Error: 401 (未认证)

// [FILE: server/routes/products.ts]
// 商品相关 API
// - GET /api/v1/products - 获取商品列表
//   Query: { page?: number, limit?: number, category?: string, search?: string, sortBy?: string, order?: 'asc' | 'desc' }
//   Response 200: { success: true, data: Product[], pagination: PaginationInfo }
//
// - GET /api/v1/products/:id - 获取商品详情
//   Response 200: { success: true, data: Product }
//   Error: 404 (商品不存在)
//
// - POST /api/v1/products - 创建商品 (管理员)
//   Request: { name: string, description: string, price: number, stock: number, image_url?: string, category: string }
//   Response 201: { success: true, data: Product }
//   Error: 400 (参数验证失败), 401 (未认证), 403 (无权限)
//
// - PUT /api/v1/products/:id - 更新商品 (管理员)
//   Request: { name?: string, description?: string, price?: number, stock?: number, image_url?: string, category?: string }
//   Response 200: { success: true, data: Product }
//   Error: 400 (参数验证失败), 401 (未认证), 403 (无权限), 404 (商品不存在)
//
// - DELETE /api/v1/products/:id - 删除商品 (管理员)
//   Response 200: { success: true, message: string }
//   Error: 401 (未认证), 403 (无权限), 404 (商品不存在)

// [FILE: server/routes/cart.ts]
// 购物车相关 API
// - GET /api/v1/cart - 获取购物车内容
//   Headers: Authorization: Bearer <token>
//   Response 200: { success: true, data: Cart }
//   Error: 401 (未认证)
//
// - POST /api/v1/cart/items - 添加商品到购物车
//   Headers: Authorization: Bearer <token>
//   Request: { productId: string, quantity: number }
//   Response 201: { success: true, data: CartItem }
//   Error: 400 (库存不足), 401 (未认证), 404 (商品不存在)
//
// - PUT /api/v1/cart/items/:id - 更新购物车商品数量
//   Headers: Authorization: Bearer <token>
//   Request: { quantity: number }
//   Response 200: { success: true, data: CartItem }
//   Error: 400 (库存不足/数量必须大于0), 401 (未认证), 404 (购物车项不存在)
//
// - DELETE /api/v1/cart/items/:id - 删除购物车商品
//   Headers: Authorization: Bearer <token>
//   Response 200: { success: true, message: string }
//   Error: 401 (未认证), 404 (购物车项不存在)
//
// - DELETE /api/v1/cart - 清空购物车
//   Headers: Authorization: Bearer <token>
//   Response 200: { success: true, message: string }
//   Error: 401 (未认证)

// [FILE: server/routes/orders.ts]
// 订单相关 API
// - GET /api/v1/orders - 获取订单列表
//   Headers: Authorization: Bearer <token>
//   Query: { page?: number, limit?: number, status?: string }
//   Response 200: { success: true, data: Order[], pagination: PaginationInfo }
//   Error: 401 (未认证)
//
// - GET /api/v1/orders/:id - 获取订单详情
//   Headers: Authorization: Bearer <token>
//   Response 200: { success: true, data: Order }
//   Error: 401 (未认证), 403 (无权访问他人订单), 404 (订单不存在)
//
// - POST /api/v1/orders - 创建订单 (从购物车生成)
//   Headers: Authorization: Bearer <token>
//   Request: { shippingAddress: ShippingAddress }
//   Response 201: { success: true, data: Order }
//   Error: 400 (购物车为空/地址信息不完整), 401 (未认证)
//
// - PUT /api/v1/orders/:id/status - 更新订单状态 (管理员)
//   Headers: Authorization: Bearer <token>
//   Request: { status: OrderStatus }
//   Response 200: { success: true, data: Order }
//   Error: 400 (无效状态), 401 (未认证), 403 (无权限), 404 (订单不存在)
//
// - DELETE /api/v1/orders/:id - 取消订单 (用户自己或管理员)
//   Headers: Authorization: Bearer <token>
//   Response 200: { success: true, message: string }
//   Error: 400 (订单无法取消), 401 (未认证), 404 (订单不存在)

