  getOrders: (params?: OrderListParams) => Promise<ApiResponse<Order[]>>;
  getOrderById: (id: string) => Promise<ApiResponse<Order>>;
  createOrder: (data: CreateOrderRequest) => Promise<ApiResponse<Order>>;
  updateOrderStatus: (id: string, data: UpdateOrderStatusRequest) => Promise<ApiResponse<Order>>;
  cancelOrder: (id: string) => Promise<SuccessResponse>;
}

export interface ApiService {
  auth: AuthApi;
  products: ProductsApi;
  cart: CartApi;
  orders: OrdersApi;
}

